import React from 'react';
import { User, JobProfile, Skill } from '../types';
import { dataService } from '../services/store';
import { ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, Tooltip, BarChart, CartesianGrid, XAxis, YAxis, Bar, Legend } from 'recharts';
import { AlertCircle, CheckCircle, Award, BookOpen } from 'lucide-react';

interface EmployeeDashboardProps {
  user: User;
}

export const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({ user }) => {
  const jobProfile = user.jobProfileId ? dataService.getJobProfile(user.jobProfileId) : null;

  if (!jobProfile) {
    return (
      <div className="flex items-center justify-center h-full text-slate-500">
        No Job Profile assigned. Contact Admin.
      </div>
    );
  }

  // Calculate Gaps
  const skillAnalysis = jobProfile.skills.map(req => {
    const skillDetails = dataService.getSkill(req.skillId);
    const currentScore = dataService.getUserSkillScore(user.id, req.skillId);
    return {
      skill: skillDetails,
      required: req.requiredLevel,
      current: currentScore,
      gap: req.requiredLevel - currentScore
    };
  });

  const chartData = skillAnalysis.map(s => ({
    subject: s.skill?.name || 'Unknown',
    Required: s.required,
    Current: s.current,
    fullMark: 5,
  }));

  const gaps = skillAnalysis.filter(s => s.gap > 0);
  const compliant = skillAnalysis.filter(s => s.gap <= 0);

  // Recommendations based on gaps
  const recommendations = gaps.map(g => {
    // Ideally, we look at the level ABOVE current to find next step
    const nextLevel = g.current + 1;
    const levelDetails = g.skill?.levels[nextLevel <= 5 ? nextLevel : 5];
    return {
      skillName: g.skill?.name,
      targetLevel: nextLevel,
      certs: levelDetails?.requiredCertificates || [],
      description: levelDetails?.description
    };
  });

  return (
    <div className="space-y-8">
      {/* Header */}
      <div>
        <h2 className="text-3xl font-bold text-slate-900">Competency Dashboard</h2>
        <p className="text-slate-500 mt-1">
          {jobProfile.title} | {dataService.getAllDepartments().find(d => d.id === user.departmentId)?.name} Department
        </p>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-xs font-semibold text-slate-400 uppercase">Compliance Rate</p>
              <h3 className="text-3xl font-bold text-slate-900 mt-2">
                {Math.round((compliant.length / skillAnalysis.length) * 100)}%
              </h3>
            </div>
            <div className={`p-2 rounded-lg ${gaps.length === 0 ? 'bg-teal-100 text-teal-600' : 'bg-amber-100 text-amber-600'}`}>
              <CheckCircle size={24} />
            </div>
          </div>
          <p className="text-sm text-slate-500 mt-4">{compliant.length} of {skillAnalysis.length} skills match required levels</p>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-xs font-semibold text-slate-400 uppercase">Skill Gaps</p>
              <h3 className="text-3xl font-bold text-red-600 mt-2">{gaps.length}</h3>
            </div>
            <div className="p-2 rounded-lg bg-red-100 text-red-600">
              <AlertCircle size={24} />
            </div>
          </div>
          <p className="text-sm text-slate-500 mt-4">Skills requiring immediate attention</p>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-xs font-semibold text-slate-400 uppercase">Recommended Certs</p>
              <h3 className="text-3xl font-bold text-blue-600 mt-2">
                {recommendations.reduce((acc, curr) => acc + curr.certs.length, 0)}
              </h3>
            </div>
            <div className="p-2 rounded-lg bg-blue-100 text-blue-600">
              <Award size={24} />
            </div>
          </div>
          <p className="text-sm text-slate-500 mt-4">To close current gaps</p>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Radar Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h4 className="text-lg font-bold text-slate-800 mb-6">Skill Profile Visualization</h4>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <RadarChart cx="50%" cy="50%" outerRadius="80%" data={chartData}>
                <PolarGrid />
                <PolarAngleAxis dataKey="subject" tick={{fontSize: 12}} />
                <PolarRadiusAxis angle={30} domain={[0, 5]} />
                <Radar name="Current" dataKey="Current" stroke="#0d9488" fill="#14b8a6" fillOpacity={0.4} />
                <Radar name="Required" dataKey="Required" stroke="#ef4444" fill="#ef4444" fillOpacity={0.1} />
                <Legend />
                <Tooltip />
              </RadarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Detailed Gap Bar Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h4 className="text-lg font-bold text-slate-800 mb-6">Gap Analysis Detail</h4>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} layout="vertical" margin={{ left: 20 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={true} />
                <XAxis type="number" domain={[0, 5]} hide />
                <YAxis dataKey="subject" type="category" width={100} tick={{fontSize: 11}} />
                <Tooltip />
                <Legend />
                <Bar dataKey="Current" fill="#14b8a6" name="Current Level" barSize={20} radius={[0, 4, 4, 0]} />
                <Bar dataKey="Required" fill="#ef4444" name="Target Level" barSize={20} radius={[0, 4, 4, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Recommendations List */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 bg-slate-50">
          <h4 className="text-lg font-bold text-slate-800">Action Plan & Recommendations</h4>
        </div>
        <div className="divide-y divide-slate-100">
          {recommendations.length > 0 ? (
            recommendations.map((rec, idx) => (
              <div key={idx} className="p-6 flex flex-col md:flex-row gap-6 hover:bg-slate-50 transition-colors">
                 <div className="flex-1">
                    <div className="flex items-center gap-2 mb-2">
                       <span className="bg-red-100 text-red-700 text-xs font-bold px-2 py-1 rounded">Gap Detected</span>
                       <h5 className="font-bold text-slate-900">{rec.skillName}</h5>
                    </div>
                    <p className="text-sm text-slate-600 mb-2">Target Level {rec.targetLevel}: {rec.description}</p>
                    <div className="flex flex-wrap gap-2">
                      {rec.certs.map((cert, cIdx) => (
                        <span key={cIdx} className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-blue-50 text-blue-700 text-xs font-medium border border-blue-100">
                          <Award size={14} />
                          {cert}
                        </span>
                      ))}
                    </div>
                 </div>
                 <div className="flex items-center">
                    <button className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded-md text-sm font-medium transition-colors flex items-center gap-2 shadow-sm shadow-teal-200">
                      <BookOpen size={16} />
                      <span>Enroll in Course</span>
                    </button>
                 </div>
              </div>
            ))
          ) : (
            <div className="p-12 text-center">
              <div className="mx-auto w-12 h-12 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-4">
                <CheckCircle size={24} />
              </div>
              <h3 className="text-lg font-medium text-slate-900">You are fully compliant!</h3>
              <p className="text-slate-500">No skill gaps detected for your current job profile.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { User, JobProfile } from '../types';
import { dataService } from '../services/store';
import { UserCircle, Send, Star } from 'lucide-react';

interface AssessmentPortalProps {
  currentUser: User;
}

export const AssessmentPortal: React.FC<AssessmentPortalProps> = ({ currentUser }) => {
  const [activeTab, setActiveTab] = useState<'SELF' | 'PEER' | 'SUBORDINATE'>('SELF');
  const [selectedSubject, setSelectedSubject] = useState<User | null>(activeTab === 'SELF' ? currentUser : null);
  const [ratings, setRatings] = useState<Record<string, number>>({});
  const [submitted, setSubmitted] = useState(false);

  // Determine selectable users based on tab
  const getSubjects = () => {
    switch(activeTab) {
      case 'SELF': return [currentUser];
      case 'PEER': return dataService.getPeers(currentUser.id);
      case 'SUBORDINATE': return dataService.getSubordinates(currentUser.id);
      default: return [];
    }
  };

  const subjects = getSubjects();

  // Reset when tab changes
  React.useEffect(() => {
    if (activeTab === 'SELF') {
      setSelectedSubject(currentUser);
    } else {
      setSelectedSubject(null);
    }
    setRatings({});
    setSubmitted(false);
  }, [activeTab, currentUser]);

  const subjectJobProfile = selectedSubject?.jobProfileId ? dataService.getJobProfile(selectedSubject.jobProfileId) : null;

  const handleRatingChange = (skillId: string, rating: number) => {
    setRatings(prev => ({ ...prev, [skillId]: rating }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSubject) return;

    Object.entries(ratings).forEach(([skillId, score]) => {
      dataService.addAssessment({
        raterId: currentUser.id,
        subjectId: selectedSubject.id,
        skillId: skillId,
        score: score,
        comment: 'Assessment Portal Submission',
        type: activeTab === 'SUBORDINATE' ? 'MANAGER' : activeTab === 'SELF' ? 'SELF' : 'PEER'
      });
    });

    setSubmitted(true);
    // Reset after delay
    setTimeout(() => {
        setSubmitted(false);
        setRatings({});
        if(activeTab !== 'SELF') setSelectedSubject(null);
    }, 2000);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">

      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-900">Performance Assessment</h2>
        <div className="bg-white rounded-lg p-1 flex shadow-sm border border-slate-200">
           {(['SELF', 'PEER', 'SUBORDINATE'] as const).map(tab => (
             <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                activeTab === tab ? 'bg-teal-600 text-white shadow-sm' : 'text-slate-500 hover:bg-slate-50'
              }`}
             >
               {tab === 'SELF' ? 'Self Review' : tab === 'PEER' ? 'Peer Review' : 'Subordinates'}
             </button>
           ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {/* Selection Column */}
        {activeTab !== 'SELF' && (
          <div className="md:col-span-1 bg-white rounded-xl shadow-sm border border-slate-200 p-4 h-fit">
            <h3 className="font-semibold text-slate-700 mb-4 px-2">Select Employee</h3>
            <div className="space-y-2">
              {subjects.length > 0 ? subjects.map(sub => (
                <button
                  key={sub.id}
                  onClick={() => { setSelectedSubject(sub); setRatings({}); setSubmitted(false); }}
                  className={`w-full flex items-center gap-3 p-3 rounded-lg transition-colors text-left ${
                    selectedSubject?.id === sub.id ? 'bg-teal-50 border border-teal-200' : 'hover:bg-slate-50 border border-transparent'
                  }`}
                >
                  <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center overflow-hidden flex-shrink-0">
                    {sub.avatarUrl ? <img src={sub.avatarUrl} alt="" className="w-full h-full object-cover"/> : <UserCircle size={18} className="text-slate-500"/>}
                  </div>
                  <div>
                    <p className={`text-sm font-medium ${selectedSubject?.id === sub.id ? 'text-teal-900' : 'text-slate-700'}`}>{sub.name}</p>
                    <p className="text-xs text-slate-500 truncate">{sub.email}</p>
                  </div>
                </button>
              )) : (
                <div className="p-4 text-center text-sm text-slate-400">No employees found for this category.</div>
              )}
            </div>
          </div>
        )}

        {/* Form Column */}
        <div className={`${activeTab === 'SELF' ? 'md:col-span-3' : 'md:col-span-2'}`}>
          {selectedSubject ? (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <div className="mb-6 pb-6 border-b border-slate-100">
                <h3 className="text-xl font-bold text-slate-900">Evaluating: {selectedSubject.name}</h3>
                <p className="text-slate-500 text-sm mt-1">{subjectJobProfile?.title || 'No Job Profile'}</p>
              </div>

              {submitted ? (
                <div className="flex flex-col items-center justify-center py-12 text-teal-600 animate-fade-in">
                  <div className="bg-teal-100 p-4 rounded-full mb-4">
                    <Send size={32} />
                  </div>
                  <h4 className="text-xl font-bold">Assessment Submitted Successfully!</h4>
                </div>
              ) : (
                <form onSubmit={handleSubmit}>
                  {subjectJobProfile ? (
                    <div className="space-y-8">
                      {subjectJobProfile.skills.map(req => {
                        const skillData = dataService.getSkill(req.skillId);
                        if (!skillData) return null;

                        return (
                          <div key={req.skillId} className="bg-slate-50 p-5 rounded-lg border border-slate-200">
                            <div className="flex justify-between mb-4">
                                <div>
                                    <h4 className="font-bold text-slate-800">{skillData.name}</h4>
                                    <p className="text-xs text-slate-500 uppercase tracking-wide">{skillData.category}</p>
                                </div>
                                <div className="text-right">
                                    <span className="text-xs font-bold text-slate-400 uppercase">Target Level</span>
                                    <div className="text-lg font-bold text-slate-700">{req.requiredLevel} / 5</div>
                                </div>
                            </div>

                            <div className="space-y-3">
                                <label className="text-sm font-medium text-slate-700">Rate Proficiency:</label>
                                <div className="flex gap-2">
                                    {[1, 2, 3, 4, 5].map(score => (
                                        <button
                                            key={score}
                                            type="button"
                                            onClick={() => handleRatingChange(req.skillId, score)}
                                            className={`flex-1 py-3 rounded border transition-all ${
                                                ratings[req.skillId] === score 
                                                ? 'bg-teal-600 text-white border-teal-600 shadow-md ring-2 ring-teal-200' 
                                                : 'bg-white text-slate-600 border-slate-200 hover:border-teal-300'
                                            }`}
                                        >
                                            <span className="block text-lg font-bold">{score}</span>
                                            <span className="text-[10px] uppercase font-medium opacity-80">Lvl</span>
                                        </button>
                                    ))}
                                </div>
                                <div className="mt-2 text-xs text-slate-500 italic">
                                   Level Description: {skillData.levels[ratings[req.skillId] || 1]?.description}
                                </div>
                            </div>
                          </div>
                        );
                      })}

                      <div className="pt-4 flex justify-end">
                        <button 
                            type="submit"
                            disabled={Object.keys(ratings).length === 0}
                            className="bg-teal-600 hover:bg-teal-700 disabled:opacity-50 disabled:cursor-not-allowed text-white px-8 py-3 rounded-lg font-bold shadow-lg shadow-teal-200/50 transition-all flex items-center gap-2"
                        >
                            <Send size={18} />
                            Submit Evaluation
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="text-center py-12 text-slate-400 bg-slate-50 rounded-lg border border-dashed border-slate-300">
                      No job profile assigned to this user. Cannot perform assessment.
                    </div>
                  )}
                </form>
              )}
            </div>
          ) : (
             <div className="h-full flex flex-col items-center justify-center bg-slate-50 rounded-xl border border-dashed border-slate-300 text-slate-400 p-12">
                <UserCircle size={48} className="mb-4 opacity-50" />
                <p>Select a person from the list to begin assessment.</p>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { dataService } from '../services/store';
import { User, Role } from '../types';
import { Plus, Users, Briefcase, ChevronRight, ChevronDown, CheckCircle, Shield } from 'lucide-react';

export const AdminPanel: React.FC = () => {
  const [activeView, setActiveView] = useState<'USERS' | 'JOBS' | 'ORG'>('USERS');
  const [users, setUsers] = useState(dataService.getAllUsers());
  const [jobs, setJobs] = useState(dataService.getAllJobs());

  // Simple Org Tree Component
  const OrgTreeItem = ({ user, depth }: { user: User, depth: number }) => {
    const [expanded, setExpanded] = useState(true);
    const subordinates = dataService.getSubordinates(user.id);
    const hasSubs = subordinates.length > 0;

    return (
      <div className="select-none">
        <div 
          className="flex items-center gap-2 p-2 hover:bg-slate-50 rounded cursor-pointer border-b border-transparent hover:border-slate-100 transition-colors"
          style={{ marginLeft: `${depth * 24}px` }}
          onClick={() => setExpanded(!expanded)}
        >
            <div className={`w-5 h-5 flex items-center justify-center text-slate-400 ${!hasSubs && 'invisible'}`}>
                {expanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
            </div>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${
                user.role === Role.MANAGER ? 'bg-indigo-100 text-indigo-700' : 
                user.role === Role.ADMIN ? 'bg-slate-800 text-white' : 'bg-teal-50 text-teal-700'
            }`}>
                {user.name.charAt(0)}
            </div>
            <div>
                <p className="text-sm font-medium text-slate-800">{user.name}</p>
                <p className="text-xs text-slate-500">{dataService.getJobProfile(user.jobProfileId || '')?.title || 'No Position'}</p>
            </div>
        </div>
        {hasSubs && expanded && (
            <div className="relative">
                 {/* Tree vertical line connector */}
                <div 
                    className="absolute border-l border-slate-200 h-full" 
                    style={{ left: `${(depth * 24) + 12}px`, top: 0 }}
                ></div>
                {subordinates.map(sub => <OrgTreeItem key={sub.id} user={sub} depth={depth + 1} />)}
            </div>
        )}
      </div>
    );
  };

  const renderUsers = () => (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="p-4 border-b border-slate-100 flex justify-between items-center">
        <h3 className="font-bold text-slate-800">Employee Directory</h3>
        <button className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1">
            <Plus size={14}/> Add Employee
        </button>
      </div>
      <table className="w-full text-left text-sm">
        <thead className="bg-slate-50 text-slate-500 font-medium">
          <tr>
            <th className="p-4">Name</th>
            <th className="p-4">Role</th>
            <th className="p-4">Job Profile</th>
            <th className="p-4">Status</th>
            <th className="p-4 text-right">Action</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100">
          {users.map(u => (
            <tr key={u.id} className="hover:bg-slate-50">
              <td className="p-4 font-medium text-slate-900">{u.name} <br/><span className="text-xs font-normal text-slate-500">{u.email}</span></td>
              <td className="p-4">
                <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                    u.role === Role.ADMIN ? 'bg-slate-100 text-slate-700' : 
                    u.role === Role.MANAGER ? 'bg-indigo-50 text-indigo-700' : 'bg-green-50 text-green-700'
                }`}>
                    {u.role}
                </span>
              </td>
              <td className="p-4 text-slate-600">{dataService.getJobProfile(u.jobProfileId || '')?.title || '-'}</td>
              <td className="p-4 text-green-600 flex items-center gap-1"><CheckCircle size={14}/> Active</td>
              <td className="p-4 text-right text-blue-600 cursor-pointer hover:underline">Edit</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderJobs = () => (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="p-4 border-b border-slate-100 flex justify-between items-center">
        <h3 className="font-bold text-slate-800">Job Profiles & Requirements</h3>
        <button className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1">
            <Plus size={14}/> Create Profile
        </button>
      </div>
      <div className="divide-y divide-slate-100">
        {jobs.map(job => (
            <div key={job.id} className="p-6 hover:bg-slate-50 transition-colors group">
                <div className="flex justify-between items-start mb-4">
                    <div>
                        <h4 className="font-bold text-lg text-slate-800">{job.title}</h4>
                        <p className="text-sm text-slate-500">{job.description}</p>
                    </div>
                    <button className="text-sm text-slate-400 group-hover:text-teal-600 border border-slate-200 rounded px-3 py-1 hover:bg-white">Edit Profile</button>
                </div>
                <div className="bg-slate-50 rounded-lg p-3 border border-slate-200">
                    <p className="text-xs font-bold text-slate-400 uppercase mb-2">Required Skills Competency Matrix</p>
                    <div className="flex flex-wrap gap-2">
                        {job.skills.map(s => {
                            const skillName = dataService.getSkill(s.skillId)?.name;
                            return (
                                <div key={s.skillId} className="bg-white px-3 py-1 rounded border border-slate-200 text-xs flex items-center gap-2 shadow-sm">
                                    <span className="text-slate-700 font-medium">{skillName}</span>
                                    <span className="bg-slate-100 text-slate-600 px-1.5 rounded font-bold">Lvl {s.requiredLevel}</span>
                                </div>
                            )
                        })}
                    </div>
                </div>
            </div>
        ))}
      </div>
    </div>
  );

  const renderOrg = () => {
    // Find top level managers or admins
    const rootUsers = users.filter(u => u.role === Role.ADMIN || (u.role === Role.MANAGER && !u.managerId));

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 min-h-[500px]">
             <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                <Shield className="text-teal-600" size={20}/> Organization Structure
             </h3>
             <div className="border border-slate-100 rounded-lg p-4 bg-slate-50/50">
                {rootUsers.map(u => <OrgTreeItem key={u.id} user={u} depth={0} />)}
             </div>
        </div>
    )
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center space-x-4 border-b border-slate-200 pb-1">
        <button 
            onClick={() => setActiveView('USERS')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'USERS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Users size={16}/> Users & Approvals
        </button>
        <button 
            onClick={() => setActiveView('JOBS')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'JOBS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Briefcase size={16}/> Job Profiles
        </button>
        <button 
            onClick={() => setActiveView('ORG')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'ORG' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Shield size={16}/> Organization Tree
        </button>
      </div>

      <div className="animate-fade-in">
        {activeView === 'USERS' && renderUsers()}
        {activeView === 'JOBS' && renderJobs()}
        {activeView === 'ORG' && renderOrg()}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { EmployeeDashboard } from './pages/EmployeeDashboard';
import { AssessmentPortal } from './pages/AssessmentPortal';
import { AdminPanel } from './pages/AdminPanel';
import { dataService } from './services/store';
import { User, Role } from './types';
import { ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [email, setEmail] = useState('sara@erpom.com');
  const [activeTab, setActiveTab] = useState('emp-dashboard');
  const [error, setError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const foundUser = dataService.login(email);
    if (foundUser) {
      setUser(foundUser);
      // Set default tab based on role
      if (foundUser.role === Role.ADMIN) {
        setActiveTab('admin-dashboard');
      } else {
        setActiveTab('emp-dashboard');
      }
      setError('');
    } else {
      setError('User not found. Try: admin@erpom.com, sara@erpom.com, ahmed@erpom.com');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setEmail('');
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-900 p-4">
        <div className="bg-white rounded-xl shadow-2xl overflow-hidden max-w-md w-full">
            <div className="bg-teal-600 p-8 text-center">
                <div className="mx-auto bg-white/20 w-16 h-16 rounded-full flex items-center justify-center backdrop-blur-sm mb-4">
                    <ShieldCheck className="text-white" size={32} />
                </div>
                <h1 className="text-2xl font-bold text-white">ERPOM Competency</h1>
                <p className="text-teal-100 text-sm mt-1">Employee Skill Management System</p>
            </div>

            <form onSubmit={handleLogin} className="p-8 space-y-6">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Company Email</label>
                    <input 
                        type="email" 
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-teal-500 focus:border-transparent outline-none transition-all"
                        placeholder="name@erpom.com"
                        required
                    />
                </div>

                {error && <p className="text-red-500 text-xs bg-red-50 p-2 rounded">{error}</p>}

                <button type="submit" className="w-full bg-slate-900 hover:bg-slate-800 text-white font-bold py-3 rounded-lg transition-colors">
                    Access Portal
                </button>

                <div className="pt-4 border-t border-slate-100">
                    <p className="text-xs text-center text-slate-400">Demo Credentials:</p>
                    <div className="flex flex-wrap gap-2 justify-center mt-2">
                        <span onClick={() => setEmail('sara@erpom.com')} className="cursor-pointer px-2 py-1 bg-slate-100 rounded text-xs text-slate-600 hover:bg-slate-200">Employee</span>
                        <span onClick={() => setEmail('ahmed@erpom.com')} className="cursor-pointer px-2 py-1 bg-slate-100 rounded text-xs text-slate-600 hover:bg-slate-200">Manager</span>
                        <span onClick={() => setEmail('admin@erpom.com')} className="cursor-pointer px-2 py-1 bg-slate-100 rounded text-xs text-slate-600 hover:bg-slate-200">Admin</span>
                    </div>
                </div>
            </form>
        </div>
      </div>
    );
  }

  // Router Logic based on Tab ID
  const renderContent = () => {
    switch(activeTab) {
        case 'emp-dashboard': return <EmployeeDashboard user={user} />;
        case 'emp-assessment': return <AssessmentPortal currentUser={user} />;
        case 'admin-dashboard': // Fallthrough for demo
        case 'admin-users': 
        case 'admin-jobs': 
        case 'admin-skills': 
            return <AdminPanel />;
        default: return <div className="p-8 text-center text-slate-400">Section Under Construction</div>;
    }
  };

  return (
    <Layout 
      user={user} 
      onLogout={handleLogout} 
      activeTab={activeTab} 
      onSwitchTab={setActiveTab}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { User, JobProfile } from '../types';
import { dataService } from '../services/store';
import { UserCircle, Send, Star } from 'lucide-react';

interface AssessmentPortalProps {
  currentUser: User;
}

export const AssessmentPortal: React.FC<AssessmentPortalProps> = ({ currentUser }) => {
  const [activeTab, setActiveTab] = useState<'SELF' | 'PEER' | 'SUBORDINATE'>('SELF');
  const [selectedSubject, setSelectedSubject] = useState<User | null>(activeTab === 'SELF' ? currentUser : null);
  const [ratings, setRatings] = useState<Record<string, number>>({});
  const [submitted, setSubmitted] = useState(false);

  // Determine selectable users based on tab
  const getSubjects = () => {
    switch(activeTab) {
      case 'SELF': return [currentUser];
      case 'PEER': return dataService.getPeers(currentUser.id);
      case 'SUBORDINATE': return dataService.getSubordinates(currentUser.id);
      default: return [];
    }
  };

  const subjects = getSubjects();

  // Reset when tab changes
  React.useEffect(() => {
    if (activeTab === 'SELF') {
      setSelectedSubject(currentUser);
    } else {
      setSelectedSubject(null);
    }
    setRatings({});
    setSubmitted(false);
  }, [activeTab, currentUser]);

  const subjectJobProfile = selectedSubject?.jobProfileId ? dataService.getJobProfile(selectedSubject.jobProfileId) : null;

  const handleRatingChange = (skillId: string, rating: number) => {
    setRatings(prev => ({ ...prev, [skillId]: rating }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSubject) return;

    Object.entries(ratings).forEach(([skillId, score]) => {
      dataService.addAssessment({
        raterId: currentUser.id,
        subjectId: selectedSubject.id,
        skillId: skillId,
        score: score as number,
        comment: 'Assessment Portal Submission',
        type: activeTab === 'SUBORDINATE' ? 'MANAGER' : activeTab === 'SELF' ? 'SELF' : 'PEER'
      });
    });

    setSubmitted(true);
    // Reset after delay
    setTimeout(() => {
        setSubmitted(false);
        setRatings({});
        if(activeTab !== 'SELF') setSelectedSubject(null);
    }, 2000);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">

      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-900">Performance Assessment</h2>
        <div className="bg-white rounded-lg p-1 flex shadow-sm border border-slate-200">
           {(['SELF', 'PEER', 'SUBORDINATE'] as const).map(tab => (
             <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                activeTab === tab ? 'bg-teal-600 text-white shadow-sm' : 'text-slate-500 hover:bg-slate-50'
              }`}
             >
               {tab === 'SELF' ? 'Self Review' : tab === 'PEER' ? 'Peer Review' : 'Subordinates'}
             </button>
           ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {/* Selection Column */}
        {activeTab !== 'SELF' && (
          <div className="md:col-span-1 bg-white rounded-xl shadow-sm border border-slate-200 p-4 h-fit">
            <h3 className="font-semibold text-slate-700 mb-4 px-2">Select Employee</h3>
            <div className="space-y-2">
              {subjects.length > 0 ? subjects.map(sub => (
                <button
                  key={sub.id}
                  onClick={() => { setSelectedSubject(sub); setRatings({}); setSubmitted(false); }}
                  className={`w-full flex items-center gap-3 p-3 rounded-lg transition-colors text-left ${
                    selectedSubject?.id === sub.id ? 'bg-teal-50 border border-teal-200' : 'hover:bg-slate-50 border border-transparent'
                  }`}
                >
                  <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center overflow-hidden flex-shrink-0">
                    {sub.avatarUrl ? <img src={sub.avatarUrl} alt="" className="w-full h-full object-cover"/> : <UserCircle size={18} className="text-slate-500"/>}
                  </div>
                  <div>
                    <p className={`text-sm font-medium ${selectedSubject?.id === sub.id ? 'text-teal-900' : 'text-slate-700'}`}>{sub.name}</p>
                    <p className="text-xs text-slate-500 truncate">{sub.email}</p>
                  </div>
                </button>
              )) : (
                <div className="p-4 text-center text-sm text-slate-400">No employees found for this category.</div>
              )}
            </div>
          </div>
        )}

        {/* Form Column */}
        <div className={`${activeTab === 'SELF' ? 'md:col-span-3' : 'md:col-span-2'}`}>
          {selectedSubject ? (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <div className="mb-6 pb-6 border-b border-slate-100">
                <h3 className="text-xl font-bold text-slate-900">Evaluating: {selectedSubject.name}</h3>
                <p className="text-slate-500 text-sm mt-1">{subjectJobProfile?.title || 'No Job Profile'}</p>
              </div>

              {submitted ? (
                <div className="flex flex-col items-center justify-center py-12 text-teal-600 animate-fade-in">
                  <div className="bg-teal-100 p-4 rounded-full mb-4">
                    <Send size={32} />
                  </div>
                  <h4 className="text-xl font-bold">Assessment Submitted Successfully!</h4>
                </div>
              ) : (
                <form onSubmit={handleSubmit}>
                  {subjectJobProfile ? (
                    <div className="space-y-8">
                      {subjectJobProfile.skills.map(req => {
                        const skillData = dataService.getSkill(req.skillId);
                        if (!skillData) return null;

                        return (
                          <div key={req.skillId} className="bg-slate-50 p-5 rounded-lg border border-slate-200">
                            <div className="flex justify-between mb-4">
                                <div>
                                    <h4 className="font-bold text-slate-800">{skillData.name}</h4>
                                    <p className="text-xs text-slate-500 uppercase tracking-wide">{skillData.category}</p>
                                </div>
                                <div className="text-right">
                                    <span className="text-xs font-bold text-slate-400 uppercase">Target Level</span>
                                    <div className="text-lg font-bold text-slate-700">{req.requiredLevel} / 5</div>
                                </div>
                            </div>

                            <div className="space-y-3">
                                <label className="text-sm font-medium text-slate-700">Rate Proficiency:</label>
                                <div className="flex gap-2">
                                    {[1, 2, 3, 4, 5].map(score => (
                                        <button
                                            key={score}
                                            type="button"
                                            onClick={() => handleRatingChange(req.skillId, score)}
                                            className={`flex-1 py-3 rounded border transition-all ${
                                                ratings[req.skillId] === score 
                                                ? 'bg-teal-600 text-white border-teal-600 shadow-md ring-2 ring-teal-200' 
                                                : 'bg-white text-slate-600 border-slate-200 hover:border-teal-300'
                                            }`}
                                        >
                                            <span className="block text-lg font-bold">{score}</span>
                                            <span className="text-[10px] uppercase font-medium opacity-80">Lvl</span>
                                        </button>
                                    ))}
                                </div>
                                <div className="mt-2 text-xs text-slate-500 italic">
                                   Level Description: {skillData.levels[ratings[req.skillId] || 1]?.description}
                                </div>
                            </div>
                          </div>
                        );
                      })}

                      <div className="pt-4 flex justify-end">
                        <button 
                            type="submit"
                            disabled={Object.keys(ratings).length === 0}
                            className="bg-teal-600 hover:bg-teal-700 disabled:opacity-50 disabled:cursor-not-allowed text-white px-8 py-3 rounded-lg font-bold shadow-lg shadow-teal-200/50 transition-all flex items-center gap-2"
                        >
                            <Send size={18} />
                            Submit Evaluation
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="text-center py-12 text-slate-400 bg-slate-50 rounded-lg border border-dashed border-slate-300">
                      No job profile assigned to this user. Cannot perform assessment.
                    </div>
                  )}
                </form>
              )}
            </div>
          ) : (
             <div className="h-full flex flex-col items-center justify-center bg-slate-50 rounded-xl border border-dashed border-slate-300 text-slate-400 p-12">
                <UserCircle size={48} className="mb-4 opacity-50" />
                <p>Select a person from the list to begin assessment.</p>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { dataService } from '../services/store';
import { User, Role } from '../types';
import { Plus, Users, Briefcase, ChevronRight, ChevronDown, CheckCircle, Shield } from 'lucide-react';

// Simple Org Tree Component moved outside to be a proper React component
const OrgTreeItem: React.FC<{ user: User, depth: number }> = ({ user, depth }) => {
  const [expanded, setExpanded] = useState(true);
  const subordinates = dataService.getSubordinates(user.id);
  const hasSubs = subordinates.length > 0;

  return (
    <div className="select-none">
      <div 
        className="flex items-center gap-2 p-2 hover:bg-slate-50 rounded cursor-pointer border-b border-transparent hover:border-slate-100 transition-colors"
        style={{ marginLeft: `${depth * 24}px` }}
        onClick={() => setExpanded(!expanded)}
      >
          <div className={`w-5 h-5 flex items-center justify-center text-slate-400 ${!hasSubs && 'invisible'}`}>
              {expanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </div>
          <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${
              user.role === Role.MANAGER ? 'bg-indigo-100 text-indigo-700' : 
              user.role === Role.ADMIN ? 'bg-slate-800 text-white' : 'bg-teal-50 text-teal-700'
          }`}>
              {user.name.charAt(0)}
          </div>
          <div>
              <p className="text-sm font-medium text-slate-800">{user.name}</p>
              <p className="text-xs text-slate-500">{dataService.getJobProfile(user.jobProfileId || '')?.title || 'No Position'}</p>
          </div>
      </div>
      {hasSubs && expanded && (
          <div className="relative">
               {/* Tree vertical line connector */}
              <div 
                  className="absolute border-l border-slate-200 h-full" 
                  style={{ left: `${(depth * 24) + 12}px`, top: 0 }}
              ></div>
              {subordinates.map(sub => <OrgTreeItem key={sub.id} user={sub} depth={depth + 1} />)}
          </div>
      )}
    </div>
  );
};

