                    {[1, 2, 3, 4, 5].map(level => {
                         const lvlData = skill.levels[level];
                         return (
                            <div key={level} className="bg-white border border-slate-200 rounded-lg p-3 text-xs shadow-sm">
                                <div className="font-bold text-slate-700 mb-1 flex justify-between">
                                    <span>Level {level}</span>
                                </div>
                                <p className="text-slate-500 mb-2 leading-relaxed min-h-[40px]">{lvlData?.description || 'No description'}</p>
                                {lvlData?.requiredCertificates?.length > 0 && (
                                    <div className="flex flex-wrap gap-1 mt-2 pt-2 border-t border-slate-100">
                                        {lvlData.requiredCertificates.map((cert, i) => (
                                            <span key={i} className="px-1.5 py-0.5 bg-indigo-50 text-indigo-600 rounded text-[10px] font-medium">{cert}</span>
                                        ))}
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        ))}
      </div>
    </div>
  );

  const renderOrg = () => {
    // Find top level managers or admins
    const rootUsers = users.filter(u => u.role === Role.ADMIN || (u.role === Role.MANAGER && !u.managerId));

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 min-h-[500px]">
             <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                <Shield className="text-teal-600" size={20}/> Organization Structure
             </h3>
             <div className="border border-slate-100 rounded-lg p-4 bg-slate-50/50">
                {rootUsers.map(u => <OrgTreeItem key={u.id} user={u} depth={0} />)}
             </div>
        </div>
    )
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center space-x-4 border-b border-slate-200 pb-1">
        <button 
            onClick={() => setActiveView('USERS')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'USERS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Users size={16}/> Users & Approvals
        </button>
        <button 
            onClick={() => setActiveView('JOBS')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'JOBS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Briefcase size={16}/> Job Profiles
        </button>
        <button 
            onClick={() => setActiveView('SKILLS')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'SKILLS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <ShieldCheck size={16}/> Skill Library
        </button>
        <button 
            onClick={() => setActiveView('ORG')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'ORG' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Shield size={16}/> Organization Tree
        </button>
      </div>

      <div className="animate-fade-in">
        {activeView === 'USERS' && renderUsers()}
        {activeView === 'JOBS' && renderJobs()}
        {activeView === 'SKILLS' && renderSkills()}
        {activeView === 'ORG' && renderOrg()}
      </div>

      <Modal 
        isOpen={isModalOpen} 
        onClose={closeModal} 
        title={`${editingData ? 'Edit' : 'Add New'} ${modalType === 'USER' ? 'Employee' : modalType === 'JOB' ? 'Job Profile' : 'Skill'}`}
      >
        {modalType === 'USER' && <UserForm initialData={editingData} onSave={handleSaveUser} onCancel={closeModal} />}
        {modalType === 'JOB' && <JobForm initialData={editingData} onSave={handleSaveJob} onCancel={closeModal} />}
        {modalType === 'SKILL' && <SkillForm initialData={editingData} onSave={handleSaveSkill} onCancel={closeModal} />}
      </Modal>
    </div>
  );
};

