                                                    {isSelected && <Check size={20} className="text-teal-600 absolute right-4 top-4" />}
                                                </label>
                                            );
                                        })}
                                    </div>
                                </div>
                                );
                            })}

                            <div className="pt-6 border-t border-slate-100 flex justify-end sticky bottom-0 bg-white p-4 -mx-4 -mb-4 rounded-b-xl shadow-inner">
                                <button 
                                    type="submit"
                                    disabled={Object.keys(ratings).length !== subjectJobProfile.skills.length}
                                    className="bg-teal-600 hover:bg-teal-700 disabled:bg-slate-300 disabled:cursor-not-allowed text-white px-8 py-3 rounded-lg font-bold shadow-lg shadow-teal-200/50 transition-all flex items-center gap-2"
                                >
                                    <Send size={18} />
                                    Submit Evaluation
                                </button>
                            </div>
                            </div>
                        ) : (
                            <div className="text-center py-12 text-slate-400 bg-slate-50 rounded-lg border border-dashed border-slate-300">
                            No job profile assigned to this user. Cannot perform assessment.
                            </div>
                        )}
                        </form>
                    )}
                  </div>
              )}

              {/* VIEW: HISTORY */}
              {viewMode === 'HISTORY' && (
                  <div className="flex flex-col h-full">
                      {historyData.length > 0 ? (
                        <div className="overflow-x-auto">
                            <table className="w-full text-left text-sm">
                                <thead className="bg-slate-50 text-slate-500 font-medium border-b border-slate-200">
                                    <tr>
                                        <th className="p-4">Date</th>
                                        <th className="p-4">{activeTab === 'SELF' ? 'Evaluator' : 'Subject'}</th>
                                        <th className="p-4">Skill</th>
                                        <th className="p-4">Rating</th>
                                        <th className="p-4">Assessment Type</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {historyData.map(record => {
                                        const skillName = dataService.getSkill(record.skillId)?.name || 'Unknown Skill';
                                        const otherParty = activeTab === 'SELF' 
                                            ? dataService.getAllUsers().find(u => u.id === record.raterId)?.name 
                                            : dataService.getAllUsers().find(u => u.id === record.subjectId)?.name;

                                        return (
                                            <tr key={record.id} className="hover:bg-slate-50 transition-colors">
                                                <td className="p-4 text-slate-500">
                                                    <div className="flex items-center gap-2">
                                                        <Clock size={14}/> {new Date(record.date).toLocaleDateString()}
                                                    </div>
                                                </td>
                                                <td className="p-4 font-medium text-slate-800">{otherParty || 'Unknown'}</td>
                                                <td className="p-4 text-slate-700">{skillName}</td>
                                                <td className="p-4">
                                                    <span className={`inline-block w-8 h-8 rounded-full text-center leading-8 font-bold text-xs ${
                                                        record.score >= 4 ? 'bg-green-100 text-green-700' :
                                                        record.score >= 3 ? 'bg-blue-100 text-blue-700' :
                                                        'bg-amber-100 text-amber-700'
                                                    }`}>
                                                        {record.score}
                                                    </span>
                                                </td>
                                                <td className="p-4">
                                                    <span className="px-2 py-1 bg-slate-100 text-slate-600 rounded text-xs font-semibold">
                                                        {record.type}
                                                    </span>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                      ) : (
                          <div className="flex-1 flex flex-col items-center justify-center p-12 text-slate-400">
                              <History size={48} className="mb-4 opacity-20"/>
                              <p>No assessment history found.</p>
                          </div>
                      )}
                  </div>
              )}

            </div>
          ) : (
             <div className="h-full flex flex-col items-center justify-center bg-slate-50 rounded-xl border border-dashed border-slate-300 text-slate-400 p-12">
                <UserCircle size={48} className="mb-4 opacity-50" />
                <p>Select a person from the list to begin.</p>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { dataService } from '../services/store';
import { User, Role, JobProfile, Skill, JobProfileSkill, SkillLevel } from '../types';
import { Plus, Users, Briefcase, ChevronRight, ChevronDown, CheckCircle, Shield, ShieldCheck, X, Save, Trash2, ArrowLeft } from 'lucide-react';

// --- Modal Component ---
const Modal: React.FC<{ isOpen: boolean; onClose: () => void; title: string; children: React.ReactNode }> = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col animate-in zoom-in-95 duration-200">
        <div className="flex justify-between items-center p-6 border-b border-slate-100">
          <h3 className="text-xl font-bold text-slate-900">{title}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-700 transition-colors">
            <X size={24} />
          </button>
        </div>
        <div className="p-6 overflow-y-auto custom-scrollbar">
          {children}
        </div>
      </div>
    </div>
  );
};

// --- Forms ---

const UserForm: React.FC<{ initialData?: User | null, onSave: (u: User) => void, onCancel: () => void }> = ({ initialData, onSave, onCancel }) => {
  const [formData, setFormData] = useState<Partial<User>>(initialData || {
    role: Role.EMPLOYEE,
    departmentId: dataService.getAllDepartments()[0]?.id || ''
  });

  const departments = dataService.getAllDepartments();
  const jobProfiles = dataService.getAllJobs();
  const potentialManagers = dataService.getAllUsers(); 

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.email) return;

    const user: User = {
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      name: formData.name,
      email: formData.email,
      role: formData.role || Role.EMPLOYEE,
      departmentId: formData.departmentId || '',
      jobProfileId: formData.jobProfileId,
      managerId: formData.managerId,
      avatarUrl: formData.avatarUrl
    };
    onSave(user);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Full Name</label>
          <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
            value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
          <input required type="email" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
            value={formData.email || ''} onChange={e => setFormData({...formData, email: e.target.value})} />
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
           <label className="block text-sm font-medium text-slate-700 mb-1">Role</label>
           <select className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
             value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as Role})}>
             <option value={Role.EMPLOYEE}>Employee</option>
             <option value={Role.MANAGER}>Manager</option>
             <option value={Role.ADMIN}>Admin</option>
           </select>
        </div>
        <div>
           <label className="block text-sm font-medium text-slate-700 mb-1">Department</label>
           <select className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
             value={formData.departmentId} onChange={e => setFormData({...formData, departmentId: e.target.value})}>
             <option value="">Select Department</option>
             {departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
           </select>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
           <label className="block text-sm font-medium text-slate-700 mb-1">Job Profile</label>
           <select className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
             value={formData.jobProfileId || ''} onChange={e => setFormData({...formData, jobProfileId: e.target.value})}>
             <option value="">No Profile Assigned</option>
             {jobProfiles.map(j => <option key={j.id} value={j.id}>{j.title}</option>)}
           </select>
        </div>
        <div>
           <label className="block text-sm font-medium text-slate-700 mb-1">Manager</label>
           <select className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
             value={formData.managerId || ''} onChange={e => setFormData({...formData, managerId: e.target.value})}>
             <option value="">No Manager</option>
             {potentialManagers.filter(u => u.id !== initialData?.id).map(u => (
               <option key={u.id} value={u.id}>{u.name} ({u.role})</option>
             ))}
           </select>
