const OrgTreeItem: React.FC<{ user: User, depth: number }> = ({ user, depth }) => {
  const [expanded, setExpanded] = useState(true);
  const subordinates = dataService.getSubordinates(user.id);
  const hasSubs = subordinates.length > 0;

  return (
    <div className="select-none">
      <div 
        className="flex items-center gap-2 p-2 hover:bg-slate-50 rounded cursor-pointer border-b border-transparent hover:border-slate-100 transition-colors"
        style={{ marginLeft: `${depth * 24}px` }}
        onClick={() => setExpanded(!expanded)}
      >
          <div className={`w-5 h-5 flex items-center justify-center text-slate-400 ${!hasSubs && 'invisible'}`}>
              {expanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </div>
          <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${
              user.role === Role.MANAGER ? 'bg-indigo-100 text-indigo-700' : 
              user.role === Role.ADMIN ? 'bg-slate-800 text-white' : 'bg-teal-50 text-teal-700'
          }`}>
              {user.name.charAt(0)}
          </div>
          <div>
              <p className="text-sm font-medium text-slate-800">{user.name}</p>
              <p className="text-xs text-slate-500">{dataService.getJobProfile(user.jobProfileId || '')?.title || 'No Position'}</p>
          </div>
      </div>
      {hasSubs && expanded && (
          <div className="relative">
              <div 
                  className="absolute border-l border-slate-200 h-full" 
                  style={{ left: `${(depth * 24) + 12}px`, top: 0 }}
              ></div>
              {subordinates.map(sub => <OrgTreeItem key={sub.id} user={sub} depth={depth + 1} />)}
          </div>
      )}
    </div>
  );
};

interface AdminPanelProps {
  defaultTab?: 'USERS' | 'JOBS' | 'ORG' | 'SKILLS';
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ defaultTab = 'USERS' }) => {
  const [activeView, setActiveView] = useState(defaultTab);
  const [users, setUsers] = useState(dataService.getAllUsers());
  const [jobs, setJobs] = useState(dataService.getAllJobs());
  const [skills, setSkills] = useState(dataService.getAllSkills());

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'USER' | 'JOB' | 'SKILL' | null>(null);
  const [editingData, setEditingData] = useState<any>(null);

  // Skill Section State (Inline Editing)
  const [skillViewMode, setSkillViewMode] = useState<'LIST' | 'FORM'>('LIST');

  useEffect(() => {
    setActiveView(defaultTab);
  }, [defaultTab]);

  // Data Refresh
  const refreshData = () => {
    setUsers([...dataService.getAllUsers()]);
    setJobs([...dataService.getAllJobs()]);
    setSkills([...dataService.getAllSkills()]);
  };

  // Handlers for Modals (Users & Jobs)
  const openAddModal = (type: 'USER' | 'JOB') => {
      setModalType(type);
      setEditingData(null);
      setIsModalOpen(true);
  };

  const openEditModal = (type: 'USER' | 'JOB', data: any) => {
      setModalType(type);
      setEditingData(data);
      setIsModalOpen(true);
  };

  const closeModal = () => {
      setIsModalOpen(false);
      setEditingData(null);
      setModalType(null);
  };

  // Handlers for Skills (Inline)
  const handleEditSkillClick = (skill: Skill) => {
      setEditingData(skill);
      setSkillViewMode('FORM');
  };

  const handleAddSkillClick = () => {
      setEditingData(null);
      setSkillViewMode('FORM');
  };

  const handleSkillFormCancel = () => {
