const JobForm: React.FC<{ initialData?: JobProfile | null, onSave: (j: JobProfile) => void, onCancel: () => void }> = ({ initialData, onSave, onCancel }) => {
    const [formData, setFormData] = useState<Partial<JobProfile>>(initialData || { skills: [] });
    const allSkills = dataService.getAllSkills();
    const departments = dataService.getAllDepartments();
    const [selectedSkillId, setSelectedSkillId] = useState('');

    const addSkill = () => {
        if (!selectedSkillId) return;
        const exists = formData.skills?.some(s => s.skillId === selectedSkillId);
        if (exists) return;

        const newSkills = [...(formData.skills || []), { skillId: selectedSkillId, requiredLevel: 1 }];
        setFormData({...formData, skills: newSkills});
        setSelectedSkillId('');
    };

    const removeSkill = (skillId: string) => {
        setFormData({...formData, skills: formData.skills?.filter(s => s.skillId !== skillId)});
    };

    const updateSkillLevel = (skillId: string, level: number) => {
        setFormData({
            ...formData, 
            skills: formData.skills?.map(s => s.skillId === skillId ? {...s, requiredLevel: level} : s)
        });
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.title) return;
        onSave({
            id: initialData?.id || Math.random().toString(36).substr(2, 9),
            title: formData.title || '',
            description: formData.description || '',
            departmentId: formData.departmentId || '',
            skills: formData.skills || []
        });
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Job Title</label>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.title || ''} onChange={e => setFormData({...formData, title: e.target.value})} />
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Description</label>
                    <textarea className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" rows={2}
                        value={formData.description || ''} onChange={e => setFormData({...formData, description: e.target.value})} />
                </div>
                 <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Department</label>
                    <select className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                        value={formData.departmentId || ''} onChange={e => setFormData({...formData, departmentId: e.target.value})}>
                        <option value="">Select Department</option>
                        {departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                    </select>
                </div>
            </div>

            <div className="border-t border-slate-100 pt-4">
                <h4 className="font-bold text-slate-800 mb-3">Required Skills</h4>
                <div className="flex gap-2 mb-4">
                    <select className="flex-1 px-3 py-2 border border-slate-300 rounded-lg outline-none text-sm"
                        value={selectedSkillId} onChange={e => setSelectedSkillId(e.target.value)}>
                        <option value="">Select a skill to add...</option>
                        {allSkills.filter(s => !formData.skills?.find(fs => fs.skillId === s.id)).map(s => (
                            <option key={s.id} value={s.id}>{s.name} ({s.category})</option>
                        ))}
                    </select>
                    <button type="button" onClick={addSkill} disabled={!selectedSkillId}
                        className="bg-slate-800 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-slate-700 disabled:opacity-50">
                        Add
                    </button>
                </div>

                <div className="space-y-2">
                    {formData.skills?.length === 0 && <p className="text-sm text-slate-400 italic">No skills assigned yet.</p>}
                    {formData.skills?.map(s => {
                        const skillInfo = allSkills.find(sk => sk.id === s.skillId);
                        return (
                            <div key={s.skillId} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-200">
                                <div>
                                    <p className="font-medium text-slate-800 text-sm">{skillInfo?.name}</p>
                                    <p className="text-xs text-slate-500">{skillInfo?.category}</p>
                                </div>
                                <div className="flex items-center gap-3">
                                    <label className="text-xs font-bold text-slate-500 uppercase">Target Level:</label>
                                    <select 
                                        value={s.requiredLevel} 
                                        onChange={(e) => updateSkillLevel(s.skillId, parseInt(e.target.value))}
                                        className="px-2 py-1 rounded border border-slate-300 text-sm font-bold text-teal-700"
                                    >
                                        {[1,2,3,4,5].map(l => <option key={l} value={l}>{l}</option>)}
                                    </select>
                                    <button type="button" onClick={() => removeSkill(s.skillId)} className="text-red-400 hover:text-red-600 p-1">
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            <div className="pt-4 flex justify-end gap-3">
                <button type="button" onClick={onCancel} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors">Cancel</button>
                <button type="submit" className="px-6 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors flex items-center gap-2">
                    <Save size={18} /> Save Profile
                </button>
            </div>
        </form>
    );
};

const SkillForm: React.FC<{ initialData?: Skill | null, onSave: (s: Skill) => void, onCancel: () => void }> = ({ initialData, onSave, onCancel }) => {
    // Helper to generate empty levels if new
    const getDefaultLevels = () => {
        const levels: Record<number, SkillLevel> = {};
        for(let i=1; i<=5; i++) levels[i] = { level: i, description: '', requiredCertificates: [] };
        return levels;
    };

    const [formData, setFormData] = useState<Partial<Skill>>(initialData || { levels: getDefaultLevels() });

    const handleLevelChange = (level: number, field: keyof SkillLevel, value: any) => {
        if (!formData.levels) return;
        setFormData({
            ...formData,
            levels: {
                ...formData.levels,
                [level]: { ...formData.levels[level], [field]: value }
            }
        });
    };

    const handleCertChange = (level: number, value: string) => {
         // Split by comma
         const certs = value.split(',').map(c => c.trim()).filter(c => c !== '');
         handleLevelChange(level, 'requiredCertificates', certs);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if(!formData.name) return;
        onSave({
            id: initialData?.id || Math.random().toString(36).substr(2, 9),
            name: formData.name || '',
            category: formData.category || 'General',
            assessmentQuestion: formData.assessmentQuestion,
            levels: formData.levels as Record<number, SkillLevel>
        });
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Skill Name</label>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.category || ''} onChange={e => setFormData({...formData, category: e.target.value})} placeholder="e.g. Technical, Soft Skill"/>
                </div>
                <div className="md:col-span-2">
                    <label className="block text-sm font-medium text-slate-700 mb-1">Assessment Question</label>
                    <p className="text-xs text-slate-500 mb-2">The question managers/peers will answer to evaluate this skill.</p>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.assessmentQuestion || ''} 
                        onChange={e => setFormData({...formData, assessmentQuestion: e.target.value})} 
                        placeholder="e.g. How effectively does the employee demonstrate..."
                    />
                </div>
            </div>

            <div className="space-y-4 border-t border-slate-100 pt-4">
                <h4 className="font-bold text-slate-800">Proficiency Levels Definition</h4>
                {[1, 2, 3, 4, 5].map(level => (
                    <div key={level} className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                        <p className="font-bold text-sm text-teal-700 mb-2">Level {level}</p>
                        <div className="space-y-3">
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Behavioral Description</label>
                                <textarea required className="w-full px-3 py-2 border border-slate-300 rounded bg-white text-sm focus:ring-1 focus:ring-teal-500 outline-none" rows={2}
                                    value={formData.levels?.[level]?.description || ''} 
                                    onChange={e => handleLevelChange(level, 'description', e.target.value)}
                                    placeholder={`Describe expectations for level ${level}...`}
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Recommended Certificates (Comma separated)</label>
                                <input type="text" className="w-full px-3 py-2 border border-slate-300 rounded bg-white text-sm focus:ring-1 focus:ring-teal-500 outline-none"
                                    defaultValue={formData.levels?.[level]?.requiredCertificates?.join(', ') || ''}
                                    onBlur={e => handleCertChange(level, e.target.value)}
                                    placeholder="e.g. PMP, Safety Audit Level 1"
                                />
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="pt-4 flex justify-end gap-3 sticky bottom-0 bg-white/95 backdrop-blur py-4 border-t border-slate-100">
                <button type="button" onClick={onCancel} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors">Cancel</button>
                <button type="submit" className="px-6 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors flex items-center gap-2">
                    <Save size={18} /> Save Skill
                </button>
            </div>
        </form>
    );
};

interface AdminPanelProps {
  defaultTab?: 'USERS' | 'JOBS' | 'ORG' | 'SKILLS';
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ defaultTab = 'USERS' }) => {
  const [activeView, setActiveView] = useState(defaultTab);
  const [users, setUsers] = useState(dataService.getAllUsers());
  const [jobs, setJobs] = useState(dataService.getAllJobs());
  const [skills, setSkills] = useState(dataService.getAllSkills());
  const [departments, setDepartments] = useState(dataService.getAllDepartments());

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'USER' | 'JOB' | 'SKILL' | null>(null);
  const [editingData, setEditingData] = useState<any>(null);

  // Skill Section State (Inline Editing)
  const [skillViewMode, setSkillViewMode] = useState<'LIST' | 'FORM'>('LIST');

  // ORG Section State
  const [orgSelectedDept, setOrgSelectedDept] = useState(departments[0]?.id || '');
  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [assignTargetLevel, setAssignTargetLevel] = useState<OrgLevel | null>(null);

  useEffect(() => {
    setActiveView(defaultTab);
  }, [defaultTab]);

  useEffect(() => {
     setDepartments(dataService.getAllDepartments());
     if (!orgSelectedDept && dataService.getAllDepartments().length > 0) {
        setOrgSelectedDept(dataService.getAllDepartments()[0].id);
     }
  }, [users]); // Re-evaluate when users change

  // Data Refresh
  const refreshData = () => {
    setUsers([...dataService.getAllUsers()]);
    setJobs([...dataService.getAllJobs()]);
    setSkills([...dataService.getAllSkills()]);
    setDepartments([...dataService.getAllDepartments()]);
  };

  // Handlers for Modals (Users & Jobs)
  const openAddModal = (type: 'USER' | 'JOB') => {
      setModalType(type);
      setEditingData(null);
      setIsModalOpen(true);
  };

  const openEditModal = (type: 'USER' | 'JOB', data: any) => {
      setModalType(type);
      setEditingData(data);
      setIsModalOpen(true);
  };

  const closeModal = () => {
      setIsModalOpen(false);
      setEditingData(null);
      setModalType(null);
  };

  // Handlers for Skills (Inline)
  const handleEditSkillClick = (skill: Skill) => {
      setEditingData(skill);
      setSkillViewMode('FORM');
  };

  const handleAddSkillClick = () => {
      setEditingData(null);
      setSkillViewMode('FORM');
  };

  const handleSkillFormCancel = () => {
      setSkillViewMode('LIST');
      setEditingData(null);
  };

  // Handlers for Org Assignment
  const openAssignModal = (level: OrgLevel) => {
    setAssignTargetLevel(level);
    setIsAssignModalOpen(true);
  };

  const handleAssignUser = (userId: string) => {
    if (!assignTargetLevel) return;
    const user = users.find(u => u.id === userId);
    if (user) {
        // Update user
        const updatedUser = { 
            ...user, 
            departmentId: orgSelectedDept, // Move them to this dept
            orgLevel: assignTargetLevel 
        };
        dataService.updateUser(updatedUser);
        refreshData();
    }
    setIsAssignModalOpen(false);
    setAssignTargetLevel(null);
  };

  const handleRemoveFromOrg = (user: User) => {
      const updatedUser = { ...user, orgLevel: undefined }; // Remove level but keep in dept
      dataService.updateUser(updatedUser);
      refreshData();
  };

  // Save Handlers
  const handleSaveUser = (user: User) => {
      if (editingData) dataService.updateUser(user);
      else dataService.addUser(user);
      refreshData();
      closeModal();
  };

  const handleSaveJob = (job: JobProfile) => {
      if (editingData) dataService.updateJobProfile(job);
      else dataService.addJobProfile(job);
      refreshData();
      closeModal();
  };

  const handleSaveSkill = (skill: Skill) => {
      if (editingData) dataService.updateSkill(skill);
      else dataService.addSkill(skill);
      refreshData();
      setSkillViewMode('LIST');
      setEditingData(null);
  };

  // Render Functions

  const renderUsers = () => (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="p-4 border-b border-slate-100 flex justify-between items-center">
        <h3 className="font-bold text-slate-800">Employee Directory</h3>
        <button 
            onClick={() => openAddModal('USER')}
            className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1">
            <Plus size={14}/> Add Employee
        </button>
      </div>
      <table className="w-full text-left text-sm">
        <thead className="bg-slate-50 text-slate-500 font-medium">
          <tr>
            <th className="p-4">Name</th>
            <th className="p-4">Role</th>
            <th className="p-4">Job Profile</th>
            <th className="p-4">Status</th>
            <th className="p-4 text-right">Action</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100">
          {users.map(u => (
            <tr key={u.id} className="hover:bg-slate-50">
              <td className="p-4 font-medium text-slate-900">{u.name} <br/><span className="text-xs font-normal text-slate-500">{u.email}</span></td>
              <td className="p-4">
                <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                    u.role === Role.ADMIN ? 'bg-slate-100 text-slate-700' : 
                    u.role === Role.MANAGER ? 'bg-indigo-50 text-indigo-700' : 'bg-green-50 text-green-700'
                }`}>
                    {u.role}
                </span>
              </td>
              <td className="p-4 text-slate-600">{dataService.getJobProfile(u.jobProfileId || '')?.title || '-'}</td>
              <td className="p-4 text-green-600 flex items-center gap-1"><CheckCircle size={14}/> Active</td>
              <td className="p-4 text-right">
                <button onClick={() => openEditModal('USER', u)} className="text-blue-600 hover:underline font-medium">Edit</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderJobs = () => (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="p-4 border-b border-slate-100 flex justify-between items-center">
        <h3 className="font-bold text-slate-800">Job Profiles & Requirements</h3>
        <button 
            onClick={() => openAddModal('JOB')}
            className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1">
            <Plus size={14}/> Create Profile
        </button>
      </div>
      <div className="divide-y divide-slate-100">
        {jobs.map(job => (
            <div key={job.id} className="p-6 hover:bg-slate-50 transition-colors group">
                <div className="flex justify-between items-start mb-4">
                    <div>
                        <h4 className="font-bold text-lg text-slate-800">{job.title}</h4>
                        <p className="text-sm text-slate-500">{job.description}</p>
                    </div>
                    <button onClick={() => openEditModal('JOB', job)} className="text-sm text-slate-400 hover:text-teal-600 border border-slate-200 rounded px-3 py-1 hover:bg-white transition-colors">Edit Profile</button>
                </div>
                <div className="bg-slate-50 rounded-lg p-3 border border-slate-200">
                    <p className="text-xs font-bold text-slate-400 uppercase mb-2">Required Skills Competency Matrix</p>
                    <div className="flex flex-wrap gap-2">
                        {job.skills.map(s => {
                            const skillName = dataService.getSkill(s.skillId)?.name;
                            return (
                                <div key={s.skillId} className="bg-white px-3 py-1 rounded border border-slate-200 text-xs flex items-center gap-2 shadow-sm">
                                    <span className="text-slate-700 font-medium">{skillName}</span>
                                    <span className="bg-slate-100 text-slate-600 px-1.5 rounded font-bold">Lvl {s.requiredLevel}</span>
                                </div>
                            )
                        })}
                    </div>
                </div>
            </div>
        ))}
      </div>
    </div>
  );

  const renderSkills = () => {
    if (skillViewMode === 'FORM') {
        return (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-300">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                    <h3 className="font-bold text-slate-800 text-lg flex items-center gap-2">
                        <button onClick={handleSkillFormCancel} className="mr-2 text-slate-400 hover:text-slate-700 transition-colors">
                            <ArrowLeft size={20}/>
                        </button>
                        {editingData ? `Edit Skill: ${editingData.name}` : 'Create New Skill'}
                    </h3>
                </div>
                <div className="p-6">
                    <SkillForm initialData={editingData} onSave={handleSaveSkill} onCancel={handleSkillFormCancel} />
                </div>
            </div>
        );
    }

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center">
                <h3 className="font-bold text-slate-800">Competency Library</h3>
                <button 
                    onClick={handleAddSkillClick}
                    className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1">
                    <Plus size={14}/> Add Skill
                </button>
            </div>
            <div className="divide-y divide-slate-100">
                {skills.map(skill => (
                    <div key={skill.id} className="p-6 hover:bg-slate-50 transition-colors">
                        <div className="flex justify-between items-start mb-4">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded bg-teal-50 flex items-center justify-center text-teal-600">
                                    <ShieldCheck size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-slate-800">{skill.name}</h4>
