    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="p-6 border-b border-slate-100 flex items-center gap-3 bg-slate-50">
            <button onClick={onCancel} className="text-slate-400 hover:text-slate-700 transition-colors">
                <ArrowLeft size={20}/>
            </button>
            <h3 className="text-xl font-bold text-slate-900">{initialData ? 'Edit Employee' : 'Onboard New Employee'}</h3>
        </div>

        <form onSubmit={handleSubmit} className="p-8 max-w-4xl mx-auto space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Full Name</label>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="e.g. John Doe"/>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Email Address</label>
                    <input required type="email" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.email || ''} onChange={e => setFormData({...formData, email: e.target.value})} placeholder="john@company.com"/>
                </div>
            </div>

            <div className="p-6 bg-slate-50 rounded-xl border border-slate-200 space-y-6">
                <h4 className="font-bold text-slate-800 flex items-center gap-2">
                    <Shield size={18} className="text-teal-600"/>
                    Organizational Role
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">System Role</label>
                        <select className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white"
                            value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as Role})}>
                            <option value={Role.EMPLOYEE}>Employee</option>
                            <option value={Role.MANAGER}>Manager</option>
                            <option value={Role.ADMIN}>Admin</option>
                        </select>
                    </div>
                    <SearchableSelect 
                        label="Department"
                        options={deptOptions}
                        value={formData.departmentId || ''}
                        onChange={(val) => setFormData({...formData, departmentId: val})}
                        placeholder="Search Department..."
                    />
                </div>
            </div>

            <div className="p-6 bg-slate-50 rounded-xl border border-slate-200 space-y-6">
                <h4 className="font-bold text-slate-800 flex items-center gap-2">
                    <Briefcase size={18} className="text-teal-600"/>
