                            <ArrowLeft size={20}/>
                        </button>
                        {editingData ? `Edit Skill: ${editingData.name}` : 'Create New Skill'}
                    </h3>
                </div>
                <div className="p-6">
                    <SkillForm initialData={editingData} onSave={handleSaveSkill} onCancel={handleSkillFormCancel} />
