                                        <button 
                                            onClick={() => openAssignModal(level.code)}
                                            className="text-xs bg-white border border-slate-300 hover:border-teal-500 hover:text-teal-600 text-slate-500 px-2 py-1 rounded-md flex items-center gap-1 transition-colors"
                                        >
                                            <UserPlus size={14}/> Assign
                                        </button>
                                    </div>

                                    <div className="min-h-[40px] flex flex-wrap gap-2">
                                        {levelUsers.length > 0 ? (
                                            levelUsers.map(u => (
                                                <div key={u.id} className="flex items-center gap-2 bg-white pl-2 pr-1 py-1 rounded border border-slate-200 shadow-sm animate-in zoom-in duration-200">
                                                    <div className="w-6 h-6 rounded-full bg-indigo-100 text-indigo-700 flex items-center justify-center text-xs font-bold">
                                                        {u.name.charAt(0)}
                                                    </div>
                                                    <span className="text-sm font-medium text-slate-800">{u.name}</span>
                                                    <button 
                                                        onClick={() => handleRemoveFromOrg(u)}
                                                        className="ml-1 p-1 text-slate-300 hover:text-red-500 rounded-full hover:bg-red-50 transition-colors"
                                                    >
                                                        <X size={12}/>
                                                    </button>
                                                </div>
                                            ))
                                        ) : (
                                            <div className="w-full text-center py-2 text-xs text-slate-400 italic border-2 border-dashed border-slate-100 rounded">
                                                No one assigned to this position
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                 </div>
            </div>

            {/* Assignment Modal (Still a Modal because it's a small action) */}
            <Modal
                isOpen={isAssignModalOpen}
                onClose={() => setIsAssignModalOpen(false)}
                title={`Assign to ${assignTargetLevel ? ORG_LEVEL_LABELS[assignTargetLevel] : ''}`}
            >
                <div className="space-y-4">
                    <p className="text-sm text-slate-500">Select an employee to assign to this position. Note: This will move them to the <strong>{currentDeptName}</strong> department.</p>

                    <div className="space-y-2 max-h-[300px] overflow-y-auto custom-scrollbar border rounded-lg p-2">
                        {users.map(u => (
                            <button
                                key={u.id}
                                onClick={() => handleAssignUser(u.id)}
                                className="w-full flex items-center justify-between p-3 rounded-lg hover:bg-slate-50 border border-transparent hover:border-slate-200 transition-colors text-left"
                            >
                                <div className="flex items-center gap-3">
                                    <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-xs font-bold text-slate-600">
                                        {u.name.charAt(0)}
                                    </div>
                                    <div>
                                        <p className="text-sm font-medium text-slate-900">{u.name}</p>
                                        <p className="text-xs text-slate-500">
                                            {u.departmentId === orgSelectedDept ? 'Current Dept' : dataService.getAllDepartments().find(d=>d.id===u.departmentId)?.name || 'No Dept'} • {u.orgLevel ? ORG_LEVEL_LABELS[u.orgLevel] : 'Unassigned'}
                                        </p>
                                    </div>
                                </div>
                                {u.orgLevel === assignTargetLevel && u.departmentId === orgSelectedDept && (
                                    <CheckCircle size={16} className="text-green-500"/>
                                )}
                            </button>
                        ))}
                    </div>
                </div>
            </Modal>
        </div>
    )
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center space-x-4 border-b border-slate-200 pb-1">
        <button 
            onClick={() => { setActiveView('USERS'); setUserViewMode('LIST'); }}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'USERS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Users size={16}/> Users & Approvals
        </button>
        <button 
            onClick={() => { setActiveView('JOBS'); setJobViewMode('LIST'); }}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'JOBS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Briefcase size={16}/> Job Profiles
        </button>
        <button 
            onClick={() => setActiveView('SKILLS')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'SKILLS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <ShieldCheck size={16}/> Skill Library
        </button>
        <button 
            onClick={() => setActiveView('ORG')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'ORG' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Shield size={16}/> Organization Structure
        </button>
      </div>

      <div className="animate-fade-in">
        {activeView === 'USERS' && renderUsers()}
        {activeView === 'JOBS' && renderJobs()}
        {activeView === 'SKILLS' && renderSkills()}
        {activeView === 'ORG' && renderOrg()}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { dataService } from '../services/store';
import { User, Role, JobProfile, Skill, JobProfileSkill, SkillLevel, OrgLevel, ORG_LEVEL_LABELS } from '../types';
import { Plus, Users, Briefcase, ChevronRight, CheckCircle, Shield, ShieldCheck, X, Save, Trash2, ArrowLeft, UserPlus, Building2, Search } from 'lucide-react';
import { SearchableSelect, Option } from '../components/SearchableSelect';

// --- Modal Component (Only for simple prompts like Org Assign) ---
const Modal: React.FC<{ isOpen: boolean; onClose: () => void; title: string; children: React.ReactNode }> = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col animate-in zoom-in-95 duration-200">
        <div className="flex justify-between items-center p-6 border-b border-slate-100">
          <h3 className="text-xl font-bold text-slate-900">{title}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-700 transition-colors">
            <X size={24} />
          </button>
        </div>
        <div className="p-6 overflow-y-auto custom-scrollbar">
          {children}
        </div>
      </div>
    </div>
  );
};

// --- Forms (Inline) ---

const UserForm: React.FC<{ initialData?: User | null, onSave: (u: User) => void, onCancel: () => void }> = ({ initialData, onSave, onCancel }) => {
  const [formData, setFormData] = useState<Partial<User>>(initialData || {
    role: Role.EMPLOYEE,
    departmentId: dataService.getAllDepartments()[0]?.id || ''
  });

  const departments = dataService.getAllDepartments();
  const jobProfiles = dataService.getAllJobs();
  const potentialManagers = dataService.getAllUsers(); 

  // Options for SearchableSelects
  const deptOptions: Option[] = departments.map(d => ({ value: d.id, label: d.name }));
  const jobOptions: Option[] = jobProfiles.map(j => ({ value: j.id, label: j.title, subLabel: departments.find(d=>d.id===j.departmentId)?.name }));
  const managerOptions: Option[] = potentialManagers
    .filter(u => u.id !== initialData?.id)
    .map(u => ({ value: u.id, label: u.name, subLabel: u.role }));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.email) return;

    const user: User = {
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      name: formData.name,
      email: formData.email,
      role: formData.role || Role.EMPLOYEE,
      departmentId: formData.departmentId || '',
      jobProfileId: formData.jobProfileId,
      managerId: formData.managerId,
      avatarUrl: formData.avatarUrl,
      orgLevel: formData.orgLevel
    };
    onSave(user);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="p-6 border-b border-slate-100 flex items-center gap-3 bg-slate-50">
            <button onClick={onCancel} className="text-slate-400 hover:text-slate-700 transition-colors">
                <ArrowLeft size={20}/>
            </button>
            <h3 className="text-xl font-bold text-slate-900">{initialData ? 'Edit Employee' : 'Onboard New Employee'}</h3>
        </div>

        <form onSubmit={handleSubmit} className="p-8 max-w-4xl mx-auto space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Full Name</label>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="e.g. John Doe"/>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Email Address</label>
                    <input required type="email" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.email || ''} onChange={e => setFormData({...formData, email: e.target.value})} placeholder="john@company.com"/>
                </div>
            </div>

            <div className="p-6 bg-slate-50 rounded-xl border border-slate-200 space-y-6">
                <h4 className="font-bold text-slate-800 flex items-center gap-2">
                    <Shield size={18} className="text-teal-600"/>
                    Organizational Role
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">System Role</label>
                        <select className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white"
                            value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as Role})}>
                            <option value={Role.EMPLOYEE}>Employee</option>
                            <option value={Role.MANAGER}>Manager</option>
                            <option value={Role.ADMIN}>Admin</option>
                        </select>
                    </div>
                    <SearchableSelect 
                        label="Department"
                        options={deptOptions}
                        value={formData.departmentId || ''}
                        onChange={(val) => setFormData({...formData, departmentId: val})}
                        placeholder="Search Department..."
                    />
                </div>
            </div>

            <div className="p-6 bg-slate-50 rounded-xl border border-slate-200 space-y-6">
                <h4 className="font-bold text-slate-800 flex items-center gap-2">
                    <Briefcase size={18} className="text-teal-600"/>
                    Job & Reporting
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <SearchableSelect 
                        label="Job Profile"
                        options={jobOptions}
                        value={formData.jobProfileId || ''}
                        onChange={(val) => setFormData({...formData, jobProfileId: val})}
                        placeholder="Assign Job Profile..."
                    />
                    <SearchableSelect 
                        label="Direct Manager"
                        options={managerOptions}
                        value={formData.managerId || ''}
                        onChange={(val) => setFormData({...formData, managerId: val})}
                        placeholder="Select Manager..."
                    />
                </div>
            </div>

            <div className="pt-4 flex justify-end gap-3 border-t border-slate-100">
                <button type="button" onClick={onCancel} className="px-6 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors font-medium">Cancel</button>
                <button type="submit" className="px-8 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors flex items-center gap-2 font-bold shadow-lg shadow-slate-200">
                    <Save size={18} /> Save Employee
                </button>
            </div>
        </form>
    </div>
  );
};

const JobForm: React.FC<{ initialData?: JobProfile | null, onSave: (j: JobProfile) => void, onCancel: () => void }> = ({ initialData, onSave, onCancel }) => {
    const [formData, setFormData] = useState<Partial<JobProfile>>(initialData || { skills: [] });
    const allSkills = dataService.getAllSkills();
    const departments = dataService.getAllDepartments();
    const [selectedSkillId, setSelectedSkillId] = useState('');

    const deptOptions: Option[] = departments.map(d => ({ value: d.id, label: d.name }));
    const skillOptions: Option[] = allSkills
        .filter(s => !formData.skills?.find(fs => fs.skillId === s.id))
        .map(s => ({ value: s.id, label: s.name, subLabel: s.category }));

    const addSkill = () => {
        if (!selectedSkillId) return;
        const exists = formData.skills?.some(s => s.skillId === selectedSkillId);
        if (exists) return;

        const newSkills = [...(formData.skills || []), { skillId: selectedSkillId, requiredLevel: 1 }];
        setFormData({...formData, skills: newSkills});
        setSelectedSkillId('');
    };

    const removeSkill = (skillId: string) => {
        setFormData({...formData, skills: formData.skills?.filter(s => s.skillId !== skillId)});
    };

    const updateSkillLevel = (skillId: string, level: number) => {
        setFormData({
            ...formData, 
            skills: formData.skills?.map(s => s.skillId === skillId ? {...s, requiredLevel: level} : s)
        });
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.title) return;
        onSave({
            id: initialData?.id || Math.random().toString(36).substr(2, 9),
            title: formData.title || '',
            description: formData.description || '',
            departmentId: formData.departmentId || '',
            skills: formData.skills || []
        });
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center gap-3 bg-slate-50">
                <button onClick={onCancel} className="text-slate-400 hover:text-slate-700 transition-colors">
                    <ArrowLeft size={20}/>
                </button>
                <h3 className="text-xl font-bold text-slate-900">{initialData ? `Edit: ${initialData.title}` : 'Create New Job Profile'}</h3>
            </div>

            <form onSubmit={handleSubmit} className="p-8 max-w-4xl mx-auto space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Job Title</label>
                        <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                            value={formData.title || ''} onChange={e => setFormData({...formData, title: e.target.value})} />
                    </div>
                    <SearchableSelect 
                        label="Department"
                        options={deptOptions}
                        value={formData.departmentId || ''}
                        onChange={(val) => setFormData({...formData, departmentId: val})}
                        placeholder="Search Department..."
                    />
                    <div className="md:col-span-2">
                        <label className="block text-sm font-medium text-slate-700 mb-1">Description</label>
                        <textarea className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" rows={3}
                            value={formData.description || ''} onChange={e => setFormData({...formData, description: e.target.value})} />
                    </div>
                </div>

                <div className="border-t border-slate-100 pt-6">
                    <h4 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
                        <ShieldCheck size={18} className="text-teal-600"/>
                        Competency Requirements
                    </h4>

                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mb-6">
                        <label className="block text-sm font-bold text-slate-700 mb-2">Add Competency to Profile</label>
                        <div className="flex gap-2">
                            <div className="flex-1">
                                <SearchableSelect 
                                    label=""
                                    options={skillOptions}
                                    value={selectedSkillId}
                                    onChange={setSelectedSkillId}
                                    placeholder="Search competency library..."
                                />
                            </div>
                            <button type="button" onClick={addSkill} disabled={!selectedSkillId}
                                className="bg-slate-900 text-white px-6 py-2 rounded-lg text-sm font-bold hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors h-[42px] mt-1">
                                Add
                            </button>
                        </div>
                    </div>

                    <div className="space-y-3">
                        {formData.skills?.length === 0 && (
                            <div className="text-center py-8 text-slate-400 border-2 border-dashed border-slate-100 rounded-xl">
                                No skills assigned yet. Add from the library above.
                            </div>
                        )}
                        {formData.skills?.map(s => {
                            const skillInfo = allSkills.find(sk => sk.id === s.skillId);
                            return (
                                <div key={s.skillId} className="flex items-center justify-between p-4 bg-white rounded-xl border border-slate-200 shadow-sm transition-shadow hover:shadow-md">
                                    <div className="flex items-center gap-3">
                                        <div className="w-8 h-8 rounded-lg bg-teal-50 flex items-center justify-center text-teal-600 font-bold text-xs">
                                            {s.requiredLevel}
                                        </div>
                                        <div>
                                            <p className="font-bold text-slate-800 text-sm">{skillInfo?.name}</p>
                                            <p className="text-xs text-slate-500">{skillInfo?.category}</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-4">
                                        <div className="flex flex-col items-end">
                                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Required Level</label>
                                            <div className="flex items-center gap-1 bg-slate-100 rounded-lg p-1">
                                                {[1,2,3,4,5].map(l => (
                                                    <button 
                                                        key={l}
                                                        type="button"
                                                        onClick={() => updateSkillLevel(s.skillId, l)}
                                                        className={`w-6 h-6 rounded text-xs font-bold transition-colors ${
                                                            s.requiredLevel === l ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'
                                                        }`}
                                                    >
                                                        {l}
                                                    </button>
                                                ))}
                                            </div>
                                        </div>
                                        <button type="button" onClick={() => removeSkill(s.skillId)} className="text-slate-300 hover:text-red-500 p-2 transition-colors">
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                <div className="pt-4 flex justify-end gap-3 border-t border-slate-100">
                    <button type="button" onClick={onCancel} className="px-6 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors font-medium">Cancel</button>
                    <button type="submit" className="px-8 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors flex items-center gap-2 font-bold shadow-lg shadow-slate-200">
                        <Save size={18} /> Save Profile
                    </button>
                </div>
            </form>
        </div>
    );
};

const SkillForm: React.FC<{ initialData?: Skill | null, onSave: (s: Skill) => void, onCancel: () => void }> = ({ initialData, onSave, onCancel }) => {
    // Helper to generate empty levels if new
    const getDefaultLevels = () => {
        const levels: Record<number, SkillLevel> = {};
        for(let i=1; i<=5; i++) levels[i] = { level: i, description: '', requiredCertificates: [] };
        return levels;
    };

    const [formData, setFormData] = useState<Partial<Skill>>(initialData || { levels: getDefaultLevels() });

    const handleLevelChange = (level: number, field: keyof SkillLevel, value: any) => {
        if (!formData.levels) return;
        setFormData({
            ...formData,
            levels: {
                ...formData.levels,
                [level]: { ...formData.levels[level], [field]: value }
            }
        });
    };

    const handleCertChange = (level: number, value: string) => {
         // Split by comma
         const certs = value.split(',').map(c => c.trim()).filter(c => c !== '');
         handleLevelChange(level, 'requiredCertificates', certs);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if(!formData.name) return;
        onSave({
            id: initialData?.id || Math.random().toString(36).substr(2, 9),
            name: formData.name || '',
            category: formData.category || 'General',
            assessmentQuestion: formData.assessmentQuestion,
            levels: formData.levels as Record<number, SkillLevel>
        });
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Skill Name</label>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.category || ''} onChange={e => setFormData({...formData, category: e.target.value})} placeholder="e.g. Technical, Soft Skill"/>
                </div>
                <div className="md:col-span-2">
                    <label className="block text-sm font-medium text-slate-700 mb-1">Assessment Question</label>
                    <p className="text-xs text-slate-500 mb-2">The question managers/peers will answer to evaluate this skill.</p>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.assessmentQuestion || ''} 
                        onChange={e => setFormData({...formData, assessmentQuestion: e.target.value})} 
                        placeholder="e.g. How effectively does the employee demonstrate..."
                    />
                </div>
            </div>

            <div className="space-y-4 border-t border-slate-100 pt-4">
                <h4 className="font-bold text-slate-800">Proficiency Levels Definition</h4>
                {[1, 2, 3, 4, 5].map(level => (
                    <div key={level} className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                        <p className="font-bold text-sm text-teal-700 mb-2">Level {level}</p>
                        <div className="space-y-3">
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Behavioral Description</label>
                                <textarea required className="w-full px-3 py-2 border border-slate-300 rounded bg-white text-sm focus:ring-1 focus:ring-teal-500 outline-none" rows={2}
                                    value={formData.levels?.[level]?.description || ''} 
                                    onChange={e => handleLevelChange(level, 'description', e.target.value)}
                                    placeholder={`Describe expectations for level ${level}...`}
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Recommended Certificates (Comma separated)</label>
                                <input type="text" className="w-full px-3 py-2 border border-slate-300 rounded bg-white text-sm focus:ring-1 focus:ring-teal-500 outline-none"
                                    defaultValue={formData.levels?.[level]?.requiredCertificates?.join(', ') || ''}
                                    onBlur={e => handleCertChange(level, e.target.value)}
                                    placeholder="e.g. PMP, Safety Audit Level 1"
                                />
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="pt-4 flex justify-end gap-3 sticky bottom-0 bg-white/95 backdrop-blur py-4 border-t border-slate-100">
                <button type="button" onClick={onCancel} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors">Cancel</button>
                <button type="submit" className="px-6 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors flex items-center gap-2">
                    <Save size={18} /> Save Skill
                </button>
            </div>
        </form>
    );
};

interface AdminPanelProps {
  defaultTab?: 'USERS' | 'JOBS' | 'ORG' | 'SKILLS';
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ defaultTab = 'USERS' }) => {
  const [activeView, setActiveView] = useState(defaultTab);
  const [users, setUsers] = useState(dataService.getAllUsers());
  const [jobs, setJobs] = useState(dataService.getAllJobs());
  const [skills, setSkills] = useState(dataService.getAllSkills());
  const [departments, setDepartments] = useState(dataService.getAllDepartments());

  // View Modes for each tab
  const [userViewMode, setUserViewMode] = useState<'LIST' | 'FORM'>('LIST');
  const [jobViewMode, setJobViewMode] = useState<'LIST' | 'FORM'>('LIST');
  const [skillViewMode, setSkillViewMode] = useState<'LIST' | 'FORM'>('LIST');

  // Shared Editing State
  const [editingData, setEditingData] = useState<any>(null);

  // ORG Section State
  const [orgSelectedDept, setOrgSelectedDept] = useState(departments[0]?.id || '');
  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [assignTargetLevel, setAssignTargetLevel] = useState<OrgLevel | null>(null);
  const [orgSearch, setOrgSearch] = useState('');
  const [assignSearch, setAssignSearch] = useState('');

  useEffect(() => {
    setActiveView(defaultTab);
  }, [defaultTab]);

  useEffect(() => {
     setDepartments(dataService.getAllDepartments());
     if (!orgSelectedDept && dataService.getAllDepartments().length > 0) {
        setOrgSelectedDept(dataService.getAllDepartments()[0].id);
     }
  }, [users]);

  const refreshData = () => {
    setUsers([...dataService.getAllUsers()]);
    setJobs([...dataService.getAllJobs()]);
    setSkills([...dataService.getAllSkills()]);
    setDepartments([...dataService.getAllDepartments()]);
  };

  // --- Handlers ---

  const handleEditUser = (user: User) => {
      setEditingData(user);
      setUserViewMode('FORM');
  };

  const handleAddUser = () => {
      setEditingData(null);
      setUserViewMode('FORM');
  };

  const handleUserFormCancel = () => {
      setUserViewMode('LIST');
      setEditingData(null);
  };

  const handleEditJob = (job: JobProfile) => {
      setEditingData(job);
      setJobViewMode('FORM');
  };

  const handleAddJob = () => {
      setEditingData(null);
      setJobViewMode('FORM');
  };

  const handleJobFormCancel = () => {
      setJobViewMode('LIST');
      setEditingData(null);
  };

  const handleEditSkillClick = (skill: Skill) => {
      setEditingData(skill);
      setSkillViewMode('FORM');
  };

  const handleAddSkillClick = () => {
      setEditingData(null);
      setSkillViewMode('FORM');
  };

  const handleSkillFormCancel = () => {
      setSkillViewMode('LIST');
      setEditingData(null);
  };

  // --- Org Handlers ---
  const openAssignModal = (level: OrgLevel) => {
    setAssignTargetLevel(level);
    setAssignSearch('');
    setIsAssignModalOpen(true);
  };

  const handleAssignUser = (userId: string) => {
    if (!assignTargetLevel) return;
    const user = users.find(u => u.id === userId);
    if (user) {
        const updatedUser = { 
            ...user, 
            departmentId: orgSelectedDept, 
            orgLevel: assignTargetLevel 
        };
        dataService.updateUser(updatedUser);
        refreshData();
    }
    setIsAssignModalOpen(false);
    setAssignTargetLevel(null);
  };

  const handleRemoveFromOrg = (user: User) => {
      const updatedUser = { ...user, orgLevel: undefined };
      dataService.updateUser(updatedUser);
      refreshData();
  };

  // --- Save Handlers ---
  const handleSaveUser = (user: User) => {
      if (editingData) dataService.updateUser(user);
      else dataService.addUser(user);
      refreshData();
      setUserViewMode('LIST');
      setEditingData(null);
  };

  const handleSaveJob = (job: JobProfile) => {
      if (editingData) dataService.updateJobProfile(job);
      else dataService.addJobProfile(job);
      refreshData();
      setJobViewMode('LIST');
      setEditingData(null);
  };

  const handleSaveSkill = (skill: Skill) => {
      if (editingData) dataService.updateSkill(skill);
      else dataService.addSkill(skill);
      refreshData();
      setSkillViewMode('LIST');
      setEditingData(null);
  };

  // --- Render Functions ---

  const renderUsers = () => {
    if (userViewMode === 'FORM') {
        return <UserForm initialData={editingData} onSave={handleSaveUser} onCancel={handleUserFormCancel} />;
    }
    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-bold text-slate-800">Employee Directory</h3>
            <button 
                onClick={handleAddUser}
                className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1">
                <Plus size={14}/> Add Employee
            </button>
        </div>
        <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-500 font-medium">
            <tr>
                <th className="p-4">Name</th>
                <th className="p-4">Role</th>
                <th className="p-4">Job Profile</th>
                <th className="p-4">Status</th>
                <th className="p-4 text-right">Action</th>
            </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
            {users.map(u => (
                <tr key={u.id} className="hover:bg-slate-50">
                <td className="p-4 font-medium text-slate-900">{u.name} <br/><span className="text-xs font-normal text-slate-500">{u.email}</span></td>
                <td className="p-4">
                    <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                        u.role === Role.ADMIN ? 'bg-slate-100 text-slate-700' : 
                        u.role === Role.MANAGER ? 'bg-indigo-50 text-indigo-700' : 'bg-green-50 text-green-700'
                    }`}>
                        {u.role}
                    </span>
                </td>
                <td className="p-4 text-slate-600">{dataService.getJobProfile(u.jobProfileId || '')?.title || '-'}</td>
                <td className="p-4 text-green-600 flex items-center gap-1"><CheckCircle size={14}/> Active</td>
                <td className="p-4 text-right">
                    <button onClick={() => handleEditUser(u)} className="text-blue-600 hover:underline font-medium">Edit</button>
                </td>
                </tr>
            ))}
            </tbody>
        </table>
        </div>
    );
  };

  const renderJobs = () => {
    if (jobViewMode === 'FORM') {
        return <JobForm initialData={editingData} onSave={handleSaveJob} onCancel={handleJobFormCancel} />;
    }
    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-bold text-slate-800">Job Profiles & Requirements</h3>
            <button 
                onClick={handleAddJob}
                className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1">
                <Plus size={14}/> Create Profile
            </button>
        </div>
        <div className="divide-y divide-slate-100">
            {jobs.map(job => (
                <div key={job.id} className="p-6 hover:bg-slate-50 transition-colors group">
                    <div className="flex justify-between items-start mb-4">
                        <div>
                            <h4 className="font-bold text-lg text-slate-800">{job.title}</h4>
                            <p className="text-sm text-slate-500">{job.description}</p>
                        </div>
                        <button onClick={() => handleEditJob(job)} className="text-sm text-slate-400 hover:text-teal-600 border border-slate-200 rounded px-3 py-1 hover:bg-white transition-colors">Edit Profile</button>
                    </div>
                    <div className="bg-slate-50 rounded-lg p-3 border border-slate-200">
                        <p className="text-xs font-bold text-slate-400 uppercase mb-2">Required Skills Competency Matrix</p>
                        <div className="flex flex-wrap gap-2">
                            {job.skills.map(s => {
                                const skillName = dataService.getSkill(s.skillId)?.name;
                                return (
                                    <div key={s.skillId} className="bg-white px-3 py-1 rounded border border-slate-200 text-xs flex items-center gap-2 shadow-sm">
                                        <span className="text-slate-700 font-medium">{skillName}</span>
                                        <span className="bg-slate-100 text-slate-600 px-1.5 rounded font-bold">Lvl {s.requiredLevel}</span>
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                </div>
            ))}
        </div>
        </div>
    );
  };

  const renderSkills = () => {
    if (skillViewMode === 'FORM') {
        return (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-300">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                    <h3 className="font-bold text-slate-800 text-lg flex items-center gap-2">
                        <button onClick={handleSkillFormCancel} className="mr-2 text-slate-400 hover:text-slate-700 transition-colors">
                            <ArrowLeft size={20}/>
                        </button>
                        {editingData ? `Edit Skill: ${editingData.name}` : 'Create New Skill'}
                    </h3>
                </div>
                <div className="p-6">
                    <SkillForm initialData={editingData} onSave={handleSaveSkill} onCancel={handleSkillFormCancel} />
                </div>
            </div>
        );
    }

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center">
                <h3 className="font-bold text-slate-800">Competency Library</h3>
                <button 
                    onClick={handleAddSkillClick}
                    className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1">
                    <Plus size={14}/> Add Skill
                </button>
            </div>
            <div className="divide-y divide-slate-100">
                {skills.map(skill => (
                    <div key={skill.id} className="p-6 hover:bg-slate-50 transition-colors">
                        <div className="flex justify-between items-start mb-4">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded bg-teal-50 flex items-center justify-center text-teal-600">
                                    <ShieldCheck size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-slate-800">{skill.name}</h4>
                                    <span className="text-xs bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full">{skill.category}</span>
                                </div>
                            </div>
                            <button onClick={() => handleEditSkillClick(skill)} className="text-xs border border-slate-300 rounded px-2 py-1 text-slate-500 hover:text-teal-600 hover:border-teal-600 transition-colors">Edit</button>
                        </div>

                        {skill.assessmentQuestion && (
                            <div className="mb-4 p-3 bg-blue-50 text-blue-800 text-sm rounded-lg border border-blue-100 italic">
                                "Q: {skill.assessmentQuestion}"
                            </div>
                        )}

                        <div className="grid grid-cols-1 md:grid-cols-5 gap-3 mt-4">
                            {[1, 2, 3, 4, 5].map(level => {
                                const lvlData = skill.levels[level];
                                return (
                                    <div key={level} className="bg-white border border-slate-200 rounded-lg p-3 text-xs shadow-sm">
                                        <div className="font-bold text-slate-700 mb-1 flex justify-between">
                                            <span>Level {level}</span>
                                        </div>
                                        <p className="text-slate-500 mb-2 leading-relaxed min-h-[40px]">{lvlData?.description || 'No description'}</p>
                                        {lvlData?.requiredCertificates?.length > 0 && (
                                            <div className="flex flex-wrap gap-1 mt-2 pt-2 border-t border-slate-100">
                                                {lvlData.requiredCertificates.map((cert, i) => (
                                                    <span key={i} className="px-1.5 py-0.5 bg-indigo-50 text-indigo-600 rounded text-[10px] font-medium">{cert}</span>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
  };

  const renderOrg = () => {
    // Defined Hierarchy Order
    const HIERARCHY: { code: OrgLevel, label: string }[] = [
        { code: 'GM', label: 'General Manager' },
        { code: 'GAM', label: 'General Assistant Manager' },
        { code: 'DM', label: 'Department Manager' },
        { code: 'DH', label: 'Department Head' },
        { code: 'EX', label: 'Excellent Position' },
        { code: 'FP', label: 'First Position' },
        { code: 'FR', label: 'Fresh' },
    ];

    const currentDeptName = departments.find(d => d.id === orgSelectedDept)?.name || 'Unknown';

    // Users available for assignment (filtering out those already in the tree?)
    // Or just all users matching search?
    const assignableUsers = users.filter(u => 
        (assignSearch === '' || u.name.toLowerCase().includes(assignSearch.toLowerCase()))
    );

    return (
        <div className="space-y-6">
            {/* Department Selector & Search */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row justify-between items-center gap-4">
                <div className="flex flex-wrap gap-2 items-center">
                    <span className="text-sm font-bold text-slate-700 mr-2 flex items-center gap-2">
                        <Building2 size={18}/> Department:
                    </span>
                    {departments.map(dept => (
                        <button
                            key={dept.id}
                            onClick={() => setOrgSelectedDept(dept.id)}
                            className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-colors ${
                                orgSelectedDept === dept.id 
                                ? 'bg-slate-800 text-white shadow-md' 
                                : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                            }`}
                        >
                            {dept.name}
                        </button>
                    ))}
                </div>

                <div className="relative w-full md:w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input 
                        type="text" 
                        value={orgSearch}
                        onChange={(e) => setOrgSearch(e.target.value)}
                        placeholder="Search employees..."
                        className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                    />
                </div>
            </div>

            {/* Hierarchy Tree */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8 min-h-[600px] flex flex-col items-center">
                 <h2 className="text-xl font-bold text-slate-800 mb-8 border-b border-slate-100 pb-4 w-full text-center">
                    {currentDeptName} Hierarchy
                 </h2>

                 <div className="w-full max-w-3xl space-y-4">
                    {HIERARCHY.map((level, index) => {
                        // Find users in this department at this level with search filter
                        const levelUsers = users.filter(u => 
                            u.departmentId === orgSelectedDept && 
                            u.orgLevel === level.code &&
                            (orgSearch === '' || u.name.toLowerCase().includes(orgSearch.toLowerCase()))
                        );

                        return (
                            <div key={level.code} className="relative">
                                {/* Connector Line */}
                                {index < HIERARCHY.length - 1 && (
                                    <div className="absolute left-1/2 -bottom-4 w-0.5 h-4 bg-slate-300 -translate-x-1/2 z-0"></div>
                                )}

                                <div className="relative z-10 bg-slate-50 border border-slate-200 rounded-lg p-4 transition-all hover:shadow-md hover:border-teal-200">
                                    <div className="flex justify-between items-center mb-2 border-b border-slate-200 pb-2">
                                        <h4 className="text-sm font-bold text-slate-500 uppercase tracking-wider">{level.label}</h4>
                                        <button 
                                            onClick={() => openAssignModal(level.code)}
                                            className="text-xs bg-white border border-slate-300 hover:border-teal-500 hover:text-teal-600 text-slate-500 px-2 py-1 rounded-md flex items-center gap-1 transition-colors"
                                        >
                                            <UserPlus size={14}/> Assign
                                        </button>
                                    </div>

                                    <div className="min-h-[40px] flex flex-wrap gap-2">
                                        {levelUsers.length > 0 ? (
                                            levelUsers.map(u => (
                                                <div key={u.id} className="flex items-center gap-2 bg-white pl-2 pr-1 py-1 rounded border border-slate-200 shadow-sm animate-in zoom-in duration-200">
                                                    <div className="w-6 h-6 rounded-full bg-indigo-100 text-indigo-700 flex items-center justify-center text-xs font-bold">
                                                        {u.name.charAt(0)}
                                                    </div>
                                                    <span className="text-sm font-medium text-slate-800">{u.name}</span>
                                                    <button 
                                                        onClick={() => handleRemoveFromOrg(u)}
                                                        className="ml-1 p-1 text-slate-300 hover:text-red-500 rounded-full hover:bg-red-50 transition-colors"
                                                    >
                                                        <X size={12}/>
                                                    </button>
                                                </div>
                                            ))
                                        ) : (
                                            <div className="w-full text-center py-2 text-xs text-slate-400 italic border-2 border-dashed border-slate-100 rounded">
                                                {orgSearch ? 'No matches found' : 'No one assigned to this position'}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                 </div>
            </div>

            {/* Assignment Modal */}
            <Modal
                isOpen={isAssignModalOpen}
                onClose={() => setIsAssignModalOpen(false)}
                title={`Assign to ${assignTargetLevel ? ORG_LEVEL_LABELS[assignTargetLevel] : ''}`}
            >
                <div className="space-y-4">
                    <p className="text-sm text-slate-500">Select an employee to assign to this position. Note: This will move them to the <strong>{currentDeptName}</strong> department.</p>

                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <input 
                             type="text" 
                             placeholder="Search users to assign..." 
                             className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:ring-1 focus:ring-teal-500 outline-none"
                             value={assignSearch}
                             onChange={(e) => setAssignSearch(e.target.value)}
                        />
                    </div>

                    <div className="space-y-2 max-h-[300px] overflow-y-auto custom-scrollbar border rounded-lg p-2">
                        {assignableUsers.map(u => (
                            <button
                                key={u.id}
                                onClick={() => handleAssignUser(u.id)}
                                className="w-full flex items-center justify-between p-3 rounded-lg hover:bg-slate-50 border border-transparent hover:border-slate-200 transition-colors text-left"
                            >
                                <div className="flex items-center gap-3">
                                    <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-xs font-bold text-slate-600">
                                        {u.name.charAt(0)}
                                    </div>
                                    <div>
                                        <p className="text-sm font-medium text-slate-900">{u.name}</p>
                                        <p className="text-xs text-slate-500">
                                            {u.departmentId === orgSelectedDept ? 'Current Dept' : dataService.getAllDepartments().find(d=>d.id===u.departmentId)?.name || 'No Dept'} • {u.orgLevel ? ORG_LEVEL_LABELS[u.orgLevel] : 'Unassigned'}
                                        </p>
                                    </div>
                                </div>
                                {u.orgLevel === assignTargetLevel && u.departmentId === orgSelectedDept && (
                                    <CheckCircle size={16} className="text-green-500"/>
                                )}
                            </button>
                        ))}
                        {assignableUsers.length === 0 && (
                            <div className="p-4 text-center text-sm text-slate-400">
                                No users found matching "{assignSearch}"
                            </div>
                        )}
                    </div>
                </div>
            </Modal>
        </div>
    )
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center space-x-4 border-b border-slate-200 pb-1">
        <button 
            onClick={() => { setActiveView('USERS'); setUserViewMode('LIST'); }}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'USERS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Users size={16}/> Users & Approvals
        </button>
        <button 
            onClick={() => { setActiveView('JOBS'); setJobViewMode('LIST'); }}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'JOBS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Briefcase size={16}/> Job Profiles
        </button>
        <button 
            onClick={() => setActiveView('SKILLS')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'SKILLS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <ShieldCheck size={16}/> Skill Library
        </button>
        <button 
            onClick={() => setActiveView('ORG')}
            className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeView === 'ORG' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
        >
            <Shield size={16}/> Organization Structure
        </button>
      </div>

      <div className="animate-fade-in">
        {activeView === 'USERS' && renderUsers()}
        {activeView === 'JOBS' && renderJobs()}
        {activeView === 'SKILLS' && renderSkills()}
        {activeView === 'ORG' && renderOrg()}
      </div>
    </div>
  );
};

export enum Role {
  ADMIN = 'ADMIN',
  EMPLOYEE = 'EMPLOYEE',
  MANAGER = 'MANAGER'
}

// The 7 specific hierarchy levels requested
export type OrgLevel = 'GM' | 'GAM' | 'DM' | 'DH' | 'EX' | 'FP' | 'FR';

export const ORG_LEVEL_LABELS: Record<OrgLevel, string> = {
  'GM': 'General Manager',
  'GAM': 'General Assistant Manager',
  'DM': 'Department Manager',
  'DH': 'Department Head',
  'EX': 'Excellent Position',
  'FP': 'First Position',
  'FR': 'Fresh'
};

// Strict Hierarchy Order (Top to Bottom)
export const ORG_HIERARCHY_ORDER: OrgLevel[] = ['GM', 'GAM', 'DM', 'DH', 'EX', 'FP', 'FR'];

export interface SkillLevel {
  level: number;
  description: string;
  requiredCertificates: string[];
}

export interface Skill {
  id: string;
  name: string;
  category: string;
  assessmentQuestion?: string;
  levels: Record<number, SkillLevel>; 
}

export interface JobProfileSkill {
  skillId: string;
  requiredLevel: number; // 1-5
}

export interface JobProfile {
  id: string;
  title: string;
  description: string;
  departmentId: string;
  skills: JobProfileSkill[];
}

export interface Department {
  id: string;
  name: string;
  managerId?: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: Role;
  departmentId: string;
  orgLevel?: OrgLevel; // Position in the hierarchy
  jobProfileId?: string;
  managerId?: string; // Direct reporting line (can be inferred from structure or explicit)
  avatarUrl?: string;
}

export interface Assessment {
  id: string;
  raterId: string;
  subjectId: string;
  skillId: string;
  score: number; // 1-5
