class DataService {
  private users: User[] = [];
  private jobs: JobProfile[] = [];
  private skills: Skill[] = [];
  private assessments: Assessment[] = [];
  private departments: Department[] = [];

  private db: any = null; // Firestore instance
  public isInitialized = false;

  constructor() {
    // We load mock data by default so the app doesn't crash before init
    this.resetToMock();
  }

  private resetToMock() {
    this.users = [...MOCK_USERS];
    this.jobs = [...MOCK_JOBS];
    this.skills = [...MOCK_SKILLS];
    this.assessments = [...MOCK_ASSESSMENTS];
    this.departments = [...MOCK_DEPTS];
  }

  // --- INITIALIZATION ---

  async initialize() {
    console.log(`Initializing DataService with SOURCE: ${CONFIG.SOURCE}`);

    if (CONFIG.SOURCE === 'FIREBASE') {
      try {
        const app = initializeApp(CONFIG.FIREBASE);
        this.db = getFirestore(app);
        await this.loadFromFirebase();
      } catch (e) {
        console.error("Firebase Connection Failed. Falling back to Mock data.", e);
        this.resetToMock();
      }
    } else if (CONFIG.SOURCE === 'API') {
      await this.loadFromApi();
    } else {
      // MOCK
      this.resetToMock();
    }

    this.isInitialized = true;
  }

  // --- LOADERS ---

  private async loadFromFirebase() {
    // Helper to fetch collection
    const fetchColl = async (name: string) => {
      const snap = await getDocs(collection(this.db, name));
      return snap.docs.map(d => d.data());
    };

    const [u, j, s, a, d] = await Promise.all([
      fetchColl('users'),
      fetchColl('jobs'),
      fetchColl('skills'),
      fetchColl('assessments'),
      fetchColl('departments')
    ]);

    // Only overwrite if remote data exists, otherwise keep mocks (or empty)
    if (u.length) this.users = u as User[];
    if (j.length) this.jobs = j as JobProfile[];
    if (s.length) this.skills = s as Skill[];
    if (a.length) this.assessments = a as Assessment[];
    if (d.length) this.departments = d as Department[];
  }

  private async loadFromApi() {
    try {
      const fetchData = async (endpoint: string) => {
        const res = await fetch(`${CONFIG.API_URL}/${endpoint}`);
        return res.json();
      };

      this.users = await fetchData('users');
      this.jobs = await fetchData('jobs');
      this.skills = await fetchData('skills');
      this.assessments = await fetchData('assessments');
      this.departments = await fetchData('departments');
    } catch (e) {
      console.error("API Connection Failed", e);
      this.resetToMock();
    }
  }

  // --- PERSISTENCE HELPERS ---

  private async persistItem(collectionName: string, item: any) {
    if (CONFIG.SOURCE === 'FIREBASE' && this.db) {
      try {
        // Use setDoc to enforce the ID we generated on the client
        await setDoc(doc(this.db, collectionName, item.id), item);
      } catch (e) {
        console.error(`Failed to save to Firebase [${collectionName}]`, e);
      }
    } else if (CONFIG.SOURCE === 'API') {
      try {
        await fetch(`${CONFIG.API_URL}/${collectionName}`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(item)
        });
      } catch (e) {
        console.error(`Failed to save to API [${collectionName}]`, e);
      }
    }
  }

  private async updateItem(collectionName: string, item: any) {
     if (CONFIG.SOURCE === 'FIREBASE' && this.db) {
       try {
         await updateDoc(doc(this.db, collectionName, item.id), item);
       } catch (e) {
         console.error(`Failed to update Firebase [${collectionName}]`, e);
       }
     } else if (CONFIG.SOURCE === 'API') {
        try {
          await fetch(`${CONFIG.API_URL}/${collectionName}/${item.id}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(item)
          });
        } catch (e) {
          console.error(`Failed to update API [${collectionName}]`, e);
        }
     }
  }

  // --- PUBLIC METHODS (GETTERS - Synchronous for UI Performance) ---

  login(email: string): User | undefined {
    return this.users.find(u => u.email.toLowerCase() === email.toLowerCase());
  }

  getCurrentUser(id: string) { return this.users.find(u => u.id === id); }
  getJobProfile(id: string) { return this.jobs.find(j => j.id === id); }
  getAllSkills() { return this.skills; }
  getAllJobs() { return this.jobs; }
  getAllUsers() { return this.users; }
  getAllDepartments() { return this.departments; }
  getSkill(id: string) { return this.skills.find(s => s.id === id); }

  // Logic: Direct Subordinates based on Organization Structure in the SAME department
  // Returns users who are exactly one level below the manager in the hierarchy within the same department.
  getSubordinates(managerId: string) {
    const manager = this.getCurrentUser(managerId);
    if (!manager || !manager.departmentId || !manager.orgLevel) return [];

    // 1. Check if specific managerId is set (Legacy/Override)
    const directReports = this.users.filter(u => u.managerId === managerId);
    if (directReports.length > 0) return directReports;

    // 2. Org Structure Logic
    const currentLevelIdx = ORG_HIERARCHY_ORDER.indexOf(manager.orgLevel);
    // If invalid level or at bottom, no subordinates
    if (currentLevelIdx === -1 || currentLevelIdx >= ORG_HIERARCHY_ORDER.length - 1) return [];

    const targetSubordinateLevel = ORG_HIERARCHY_ORDER[currentLevelIdx + 1];

    return this.users.filter(u => 
      u.departmentId === manager.departmentId && 
      u.orgLevel === targetSubordinateLevel
    );
  }

  // Logic: Peers are in the SAME department and SAME Org Level
  getPeers(userId: string) {
    const user = this.getCurrentUser(userId);
    if (!user || !user.departmentId || !user.orgLevel) return [];

    return this.users.filter(u => 
        u.id !== userId && // Not self
        u.departmentId === user.departmentId &&
        u.orgLevel === user.orgLevel
    );
  }

  getUserSkillScore(userId: string, skillId: string): number {
    const userAssessments = this.assessments.filter(a => a.subjectId === userId && a.skillId === skillId);
    if (userAssessments.length === 0) return 0;
    const sum = userAssessments.reduce((acc, curr) => acc + curr.score, 0);
    return Math.round(sum / userAssessments.length);
  }

  getAssessments(filters: { raterId?: string, subjectId?: string }) {
    return this.assessments.filter(a => {
      const matchRater = filters.raterId ? a.raterId === filters.raterId : true;
      const matchSubject = filters.subjectId ? a.subjectId === filters.subjectId : true;
      return matchRater && matchSubject;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }

  // --- ACTIONS (Async Write-Behind) ---

  addAssessment(assessment: Omit<Assessment, 'id' | 'date'>) {
    const newAssessment: Assessment = {
      ...assessment,
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString(),
    };
    // 1. Optimistic Update (Immediate UI feedback)
    this.assessments.push(newAssessment);
    // 2. Persist to DB
    this.persistItem('assessments', newAssessment);
  }

  addSkill(skill: Skill) { 
    this.skills.push(skill); 
    this.persistItem('skills', skill);
  }

  addJobProfile(job: JobProfile) { 
    this.jobs.push(job); 
    this.persistItem('jobs', job);
  }

  addUser(user: User) { 
    this.users.push(user); 
    this.persistItem('users', user);
  }

  addDepartment(dept: Department) {
    this.departments.push(dept);
    this.persistItem('departments', dept);
  }

  updateDepartment(dept: Department) {
    const idx = this.departments.findIndex(d => d.id === dept.id);
    if (idx >= 0) {
      this.departments[idx] = dept;
      this.updateItem('departments', dept);
    }
  }

  updateUser(user: User) {
    const idx = this.users.findIndex(u => u.id === user.id);
    if (idx >= 0) {
      this.users[idx] = user;
      this.updateItem('users', user);
    }
  }

  updateJobProfile(job: JobProfile) {
    const idx = this.jobs.findIndex(j => j.id === job.id);
    if (idx >= 0) {
      this.jobs[idx] = job;
      this.updateItem('jobs', job);
    }
  }

  updateSkill(skill: Skill) {
    const idx = this.skills.findIndex(s => s.id === skill.id);
    if (idx >= 0) {
      this.skills[idx] = skill;
      this.updateItem('skills', skill);
    }
  }
}

export const dataService = new DataService();

