    const [selectedSkillId, setSelectedSkillId] = useState('');

    const deptOptions: Option[] = departments.map(d => ({ value: d.id, label: d.name }));
    const skillOptions: Option[] = allSkills
        .filter(s => !formData.skills?.find(fs => fs.skillId === s.id))
        .map(s => ({ value: s.id, label: s.name, subLabel: s.category }));

    const addSkill = () => {
        if (!selectedSkillId) return;
        const exists = formData.skills?.some(s => s.skillId === selectedSkillId);
        if (exists) return;

        const newSkills = [...(formData.skills || []), { skillId: selectedSkillId, requiredLevel: 1 }];
        setFormData({...formData, skills: newSkills});
        setSelectedSkillId('');
    };

    const removeSkill = (skillId: string) => {
        setFormData({...formData, skills: formData.skills?.filter(s => s.skillId !== skillId)});
    };

    const updateSkillLevel = (skillId: string, level: number) => {
        setFormData({
            ...formData, 
            skills: formData.skills?.map(s => s.skillId === skillId ? {...s, requiredLevel: level} : s)
        });
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.title) return;
        onSave({
            id: initialData?.id || Math.random().toString(36).substr(2, 9),
            title: formData.title || '',
            description: formData.description || '',
            departmentId: formData.departmentId || '',
            skills: formData.skills || []
        });
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-300">
            <div className="p-6 border-b border-slate-100 flex items-center gap-3 bg-slate-50">
                <button onClick={onCancel} className="text-slate-400 hover:text-slate-700 transition-colors">
                    <ArrowLeft size={20}/>
                </button>
                <h3 className="text-xl font-bold text-slate-900">{initialData ? `Edit: ${initialData.title}` : 'Create New Job Profile'}</h3>
            </div>

            <form onSubmit={handleSubmit} className="p-8 max-w-4xl mx-auto space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Job Title</label>
                        <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                            value={formData.title || ''} onChange={e => setFormData({...formData, title: e.target.value})} />
                    </div>
                    <SearchableSelect 
                        label="Department"
                        options={deptOptions}
                        value={formData.departmentId || ''}
                        onChange={(val) => setFormData({...formData, departmentId: val})}
                        placeholder="Search Department..."
                    />
                    <div className="md:col-span-2">
                        <label className="block text-sm font-medium text-slate-700 mb-1">Description</label>
                        <textarea className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" rows={3}
                            value={formData.description || ''} onChange={e => setFormData({...formData, description: e.target.value})} />
                    </div>
                </div>

                <div className="border-t border-slate-100 pt-6">
                    <h4 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
                        <ShieldCheck size={18} className="text-teal-600"/>
                        Competency Requirements
                    </h4>

                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mb-6">
                        <label className="block text-sm font-bold text-slate-700 mb-2">Add Competency to Profile</label>
                        <div className="flex gap-2">
                            <div className="flex-1">
                                <SearchableSelect 
                                    label=""
                                    options={skillOptions}
                                    value={selectedSkillId}
                                    onChange={setSelectedSkillId}
                                    placeholder="Search competency library..."
                                />
                            </div>
                            <button type="button" onClick={addSkill} disabled={!selectedSkillId}
                                className="bg-slate-900 text-white px-6 py-2 rounded-lg text-sm font-bold hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors h-[42px] mt-1">
                                Add
                            </button>
                        </div>
                    </div>

                    <div className="space-y-3">
                        {formData.skills?.length === 0 && (
                            <div className="text-center py-8 text-slate-400 border-2 border-dashed border-slate-100 rounded-xl">
                                No skills assigned yet. Add from the library above.
                            </div>
                        )}
                        {formData.skills?.map(s => {
                            const skillInfo = allSkills.find(sk => sk.id === s.skillId);
                            return (
                                <div key={s.skillId} className="flex items-center justify-between p-4 bg-white rounded-xl border border-slate-200 shadow-sm transition-shadow hover:shadow-md">
                                    <div className="flex items-center gap-3">
                                        <div className="w-8 h-8 rounded-lg bg-teal-50 flex items-center justify-center text-teal-600 font-bold text-xs">
                                            {s.requiredLevel}
                                        </div>
                                        <div>
                                            <p className="font-bold text-slate-800 text-sm">{skillInfo?.name}</p>
                                            <p className="text-xs text-slate-500">{skillInfo?.category}</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-4">
                                        <div className="flex flex-col items-end">
                                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Required Level</label>
                                            <div className="flex items-center gap-1 bg-slate-100 rounded-lg p-1">
                                                {[1,2,3,4,5].map(l => (
                                                    <button 
                                                        key={l}
                                                        type="button"
                                                        onClick={() => updateSkillLevel(s.skillId, l)}
                                                        className={`w-6 h-6 rounded text-xs font-bold transition-colors ${
                                                            s.requiredLevel === l ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'
                                                        }`}
                                                    >
                                                        {l}
                                                    </button>
                                                ))}
                                            </div>
                                        </div>
                                        <button type="button" onClick={() => removeSkill(s.skillId)} className="text-slate-300 hover:text-red-500 p-2 transition-colors">
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                <div className="pt-4 flex justify-end gap-3 border-t border-slate-100">
                    <button type="button" onClick={onCancel} className="px-6 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors font-medium">Cancel</button>
                    <button type="submit" className="px-8 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors flex items-center gap-2 font-bold shadow-lg shadow-slate-200">
                        <Save size={18} /> Save Profile
                    </button>
                </div>
            </form>
        </div>
    );
};

const SkillForm: React.FC<{ initialData?: Skill | null, onSave: (s: Skill) => void, onCancel: () => void }> = ({ initialData, onSave, onCancel }) => {
    // Helper to generate empty levels if new
    const getDefaultLevels = () => {
        const levels: Record<number, SkillLevel> = {};
        for(let i=1; i<=5; i++) levels[i] = { level: i, description: '', requiredCertificates: [] };
        return levels;
    };

    const [formData, setFormData] = useState<Partial<Skill>>(initialData || { levels: getDefaultLevels() });

    const handleLevelChange = (level: number, field: keyof SkillLevel, value: any) => {
        if (!formData.levels) return;
        setFormData({
            ...formData,
            levels: {
                ...formData.levels,
                [level]: { ...formData.levels[level], [field]: value }
            }
        });
    };

    const handleCertChange = (level: number, value: string) => {
         // Split by comma
         const certs = value.split(',').map(c => c.trim()).filter(c => c !== '');
         handleLevelChange(level, 'requiredCertificates', certs);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if(!formData.name) return;
        onSave({
            id: initialData?.id || Math.random().toString(36).substr(2, 9),
            name: formData.name || '',
            category: formData.category || 'General',
            assessmentQuestion: formData.assessmentQuestion,
            levels: formData.levels as Record<number, SkillLevel>
        });
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Skill Name</label>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.category || ''} onChange={e => setFormData({...formData, category: e.target.value})} placeholder="e.g. Technical, Soft Skill"/>
                </div>
                <div className="md:col-span-2">
                    <label className="block text-sm font-medium text-slate-700 mb-1">Assessment Question</label>
                    <p className="text-xs text-slate-500 mb-2">The question managers/peers will answer to evaluate this skill.</p>
                    <input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
                        value={formData.assessmentQuestion || ''} 
                        onChange={e => setFormData({...formData, assessmentQuestion: e.target.value})} 
                        placeholder="e.g. How effectively does the employee demonstrate..."
                    />
                </div>
            </div>

            <div className="space-y-4 border-t border-slate-100 pt-4">
                <h4 className="font-bold text-slate-800">Proficiency Levels Definition</h4>
                {[1, 2, 3, 4, 5].map(level => (
                    <div key={level} className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                        <p className="font-bold text-sm text-teal-700 mb-2">Level {level}</p>
                        <div className="space-y-3">
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Behavioral Description</label>
                                <textarea required className="w-full px-3 py-2 border border-slate-300 rounded bg-white text-sm focus:ring-1 focus:ring-teal-500 outline-none" rows={2}
                                    value={formData.levels?.[level]?.description || ''} 
                                    onChange={e => handleLevelChange(level, 'description', e.target.value)}
                                    placeholder={`Describe expectations for level ${level}...`}
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Recommended Certificates (Comma separated)</label>
                                <input type="text" className="w-full px-3 py-2 border border-slate-300 rounded bg-white text-sm focus:ring-1 focus:ring-teal-500 outline-none"
                                    defaultValue={formData.levels?.[level]?.requiredCertificates?.join(', ') || ''}
                                    onBlur={e => handleCertChange(level, e.target.value)}
                                    placeholder="e.g. PMP, Safety Audit Level 1"
                                />
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="pt-4 flex justify-end gap-3 sticky bottom-0 bg-white/95 backdrop-blur py-4 border-t border-slate-100">
                <button type="button" onClick={onCancel} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors">Cancel</button>
                <button type="submit" className="px-6 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors flex items-center gap-2">
                    <Save size={18} /> Save Skill
                </button>
            </div>
        </form>
    );
};

interface AdminPanelProps {
