                                const lvlData = skill.levels[level];
                                return (
                                    <div key={level} className="bg-white border border-slate-200 rounded-lg p-3 text-xs shadow-sm">
                                        <div className="font-bold text-slate-700 mb-1 flex justify-between">
                                            <span>Level {level}</span>
                                        </div>
                                        <p className="text-slate-500 mb-2 leading-relaxed min-h-[40px]">{lvlData?.description || 'No description'}</p>
                                        {lvlData?.requiredCertificates?.length > 0 && (
                                            <div className="flex flex-wrap gap-1 mt-2 pt-2 border-t border-slate-100">
                                                {lvlData.requiredCertificates.map((cert, i) => (
                                                    <span key={i} className="px-1.5 py-0.5 bg-indigo-50 text-indigo-600 rounded text-[10px] font-medium">{cert}</span>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
  };

  const renderDepartments = () => {
    if (deptViewMode === 'FORM') {
        return <DepartmentForm initialData={editingData} onSave={handleSaveDept} onCancel={handleDeptFormCancel} />;
    }
    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center">
                <h3 className="font-bold text-slate-800">Departments</h3>
                <button 
                    onClick={handleAddDept}
                    className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1">
                    <Plus size={14}/> Add Department
                </button>
            </div>
            <div className="divide-y divide-slate-100">
                {departments.map(dept => (
                    <div key={dept.id} className="p-6 hover:bg-slate-50 transition-colors flex justify-between items-center group">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center">
                                <Building2 size={24} />
                            </div>
                            <div>
                                <h4 className="font-bold text-lg text-slate-800">{dept.name}</h4>
                                <p className="text-xs text-slate-500">
                                    {users.filter(u => u.departmentId === dept.id).length} Employees assigned
                                </p>
                            </div>
                        </div>
                        <button 
                            onClick={() => handleEditDept(dept)}
                            className="text-slate-400 hover:text-teal-600 p-2 rounded-full hover:bg-slate-100 transition-colors"
                        >
                            <Edit2 size={18} />
                        </button>
                    </div>
                ))}
                {departments.length === 0 && (
                    <div className="p-12 text-center text-slate-400">
                        No departments found. Create one to get started.
                    </div>
                )}
            </div>
        </div>
    );
  };

  const renderOrg = () => {
    // Defined Hierarchy Order
    const HIERARCHY: { code: OrgLevel, label: string }[] = [
        { code: 'GM', label: 'General Manager' },
        { code: 'GAM', label: 'General Assistant Manager' },
        { code: 'DM', label: 'Department Manager' },
        { code: 'DH', label: 'Department Head' },
        { code: 'EX', label: 'Excellent Position' },
        { code: 'FP', label: 'First Position' },
        { code: 'FR', label: 'Fresh' },
    ];

    const currentDeptName = departments.find(d => d.id === orgSelectedDept)?.name || 'Unknown';

