                    {departments.map(dept => (
                        <button
                            key={dept.id}
                            onClick={() => setOrgSelectedDept(dept.id)}
                            className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-colors ${
                                orgSelectedDept === dept.id 
                                ? 'bg-slate-800 text-white shadow-md' 
                                : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                            }`}
                        >
                            {dept.name}
                        </button>
                    ))}
                </div>

                <div className="relative w-full md:w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input 
                        type="text" 
                        value={orgSearch}
                        onChange={(e) => setOrgSearch(e.target.value)}
                        placeholder="Search employees..."
                        className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                    />
                </div>
            </div>

            {/* Hierarchy Tree */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8 min-h-[600px] flex flex-col items-center">
                 <h2 className="text-xl font-bold text-slate-800 mb-8 border-b border-slate-100 pb-4 w-full text-center">
                    {currentDeptName} Hierarchy
                 </h2>

                 <div className="w-full max-w-3xl space-y-4">
                    {HIERARCHY.map((level, index) => {
                        // Find users in this department at this level with search filter
                        const levelUsers = users.filter(u => 
                            u.departmentId === orgSelectedDept && 
                            u.orgLevel === level.code &&
                            (orgSearch === '' || u.name.toLowerCase().includes(orgSearch.toLowerCase()))
                        );

                        return (
                            <div key={level.code} className="relative">
                                {/* Connector Line */}
                                {index < HIERARCHY.length - 1 && (
                                    <div className="absolute left-1/2 -bottom-4 w-0.5 h-4 bg-slate-300 -translate-x-1/2 z-0"></div>
                                )}

                                <div className="relative z-10 bg-slate-50 border border-slate-200 rounded-lg p-4 transition-all hover:shadow-md hover:border-teal-200">
                                    <div className="flex justify-between items-center mb-2 border-b border-slate-200 pb-2">
                                        <h4 className="text-sm font-bold text-slate-500 uppercase tracking-wider">{level.label}</h4>
                                        <button 
                                            onClick={() => openAssignModal(level.code)}
                                            className="text-xs bg-white border border-slate-300 hover:border-teal-500 hover:text-teal-600 text-slate-500 px-2 py-1 rounded-md flex items-center gap-1 transition-colors"
                                        >
                                            <UserPlus size={14}/> Assign
