const SkillForm: React.FC<{ initialData?: Skill | null, onSave: (s: Skill) => void, onCancel: () => void }> = ({ initialData, onSave, onCancel }) => {
    const getDefaultLevels = () => {
        const levels: Record<number, SkillLevel> = {};
        for(let i=1; i<=5; i++) levels[i] = { level: i, description: '', requiredCertificates: [] };
        return levels;
    };
    const [formData, setFormData] = useState<Partial<Skill>>(initialData || { levels: getDefaultLevels() });
    const handleLevelChange = (level: number, field: keyof SkillLevel, value: any) => {
        if (!formData.levels) return;
        setFormData({ ...formData, levels: { ...formData.levels, [level]: { ...formData.levels[level], [field]: value } } });
    };
    const handleCertChange = (level: number, value: string) => {
         const certs = value.split(',').map(c => c.trim()).filter(c => c !== '');
         handleLevelChange(level, 'requiredCertificates', certs);
    };
    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if(!formData.name) return;
        onSave({
            id: initialData?.id || Math.random().toString(36).substr(2, 9),
            name: formData.name || '',
            category: formData.category || 'General',
            assessmentQuestion: formData.assessmentQuestion,
            levels: formData.levels as Record<number, SkillLevel>
        });
    };
    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div><label className="block text-sm font-medium text-slate-700 mb-1">Skill Name</label><input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} /></div>
                <div><label className="block text-sm font-medium text-slate-700 mb-1">Category</label><input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" value={formData.category || ''} onChange={e => setFormData({...formData, category: e.target.value})} placeholder="e.g. Technical, Soft Skill"/></div>
                <div className="md:col-span-2"><label className="block text-sm font-medium text-slate-700 mb-1">Assessment Question</label><p className="text-xs text-slate-500 mb-2">The question managers/peers will answer to evaluate this skill.</p><input required type="text" className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" value={formData.assessmentQuestion || ''} onChange={e => setFormData({...formData, assessmentQuestion: e.target.value})} placeholder="e.g. How effectively does the employee demonstrate..."/></div>
            </div>
            <div className="space-y-4 border-t border-slate-100 pt-4"><h4 className="font-bold text-slate-800">Proficiency Levels Definition</h4>{[1, 2, 3, 4, 5].map(level => (<div key={level} className="bg-slate-50 p-4 rounded-lg border border-slate-200"><p className="font-bold text-sm text-teal-700 mb-2">Level {level}</p><div className="space-y-3"><div><label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Behavioral Description</label><textarea required className="w-full px-3 py-2 border border-slate-300 rounded bg-white text-sm focus:ring-1 focus:ring-teal-500 outline-none" rows={2} value={formData.levels?.[level]?.description || ''} onChange={e => handleLevelChange(level, 'description', e.target.value)} placeholder={`Describe expectations for level ${level}...`}/></div><div><label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Recommended Certificates (Comma separated)</label><input type="text" className="w-full px-3 py-2 border border-slate-300 rounded bg-white text-sm focus:ring-1 focus:ring-teal-500 outline-none" defaultValue={formData.levels?.[level]?.requiredCertificates?.join(', ') || ''} onBlur={e => handleCertChange(level, e.target.value)} placeholder="e.g. PMP, Safety Audit Level 1"/></div></div></div>))}</div>
            <div className="pt-4 flex justify-end gap-3 sticky bottom-0 bg-white/95 backdrop-blur py-4 border-t border-slate-100"><button type="button" onClick={onCancel} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors">Cancel</button><button type="submit" className="px-6 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors flex items-center gap-2"><Save size={18} /> Save Skill</button></div>
        </form>
    );
};

interface AdminPanelProps {
  defaultTab?: 'USERS' | 'JOBS' | 'ORG' | 'SKILLS' | 'DEPARTMENTS';
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ defaultTab = 'USERS' }) => {
  const [activeView, setActiveView] = useState(defaultTab);
  const [users, setUsers] = useState<User[]>(dataService.getAllUsers());
  const [jobs, setJobs] = useState<JobProfile[]>(dataService.getAllJobs());
  const [skills, setSkills] = useState<Skill[]>(dataService.getAllSkills());
  const [departments, setDepartments] = useState<Department[]>(dataService.getAllDepartments());

  // View Modes for each tab
  const [userViewMode, setUserViewMode] = useState<'LIST' | 'FORM'>('LIST');
  const [jobViewMode, setJobViewMode] = useState<'LIST' | 'FORM'>('LIST');
  const [skillViewMode, setSkillViewMode] = useState<'LIST' | 'FORM'>('LIST');
  const [deptViewMode, setDeptViewMode] = useState<'LIST' | 'FORM'>('LIST');

  // Shared Editing State
  const [editingData, setEditingData] = useState<any>(null);

  // ORG Section State
  const [orgSelectedDept, setOrgSelectedDept] = useState(departments[0]?.id || '');
  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [assignTargetLevel, setAssignTargetLevel] = useState<OrgLevel | null>(null);
  const [orgSearch, setOrgSearch] = useState('');
  const [assignSearch, setAssignSearch] = useState('');

  // Explicit Manager Assignment State in Modal
  const [assignManagerId, setAssignManagerId] = useState<string | null>(null);

  useEffect(() => {
    setActiveView(defaultTab);
  }, [defaultTab]);

  useEffect(() => {
     setDepartments(dataService.getAllDepartments());
     if (!orgSelectedDept && dataService.getAllDepartments().length > 0) {
        setOrgSelectedDept(dataService.getAllDepartments()[0].id);
     }
  }, [users, departments.length]); 

  const refreshData = () => {
    setUsers([...dataService.getAllUsers()]);
    setJobs([...dataService.getAllJobs()]);
    setSkills([...dataService.getAllSkills()]);
    setDepartments([...dataService.getAllDepartments()]);
  };

  // --- Handlers ---
  const handleEditUser = (user: User) => { setEditingData(user); setUserViewMode('FORM'); };
  const handleAddUser = () => { setEditingData(null); setUserViewMode('FORM'); };
  const handleUserFormCancel = () => { setUserViewMode('LIST'); setEditingData(null); };

  const handleEditJob = (job: JobProfile) => { setEditingData(job); setJobViewMode('FORM'); };
  const handleAddJob = () => { setEditingData(null); setJobViewMode('FORM'); };
  const handleJobFormCancel = () => { setJobViewMode('LIST'); setEditingData(null); };

  const handleEditSkillClick = (skill: Skill) => { setEditingData(skill); setSkillViewMode('FORM'); };
  const handleAddSkillClick = () => { setEditingData(null); setSkillViewMode('FORM'); };
  const handleSkillFormCancel = () => { setSkillViewMode('LIST'); setEditingData(null); };

  const handleAddDept = () => { setEditingData(null); setDeptViewMode('FORM'); };
  const handleEditDept = (dept: Department) => { setEditingData(dept); setDeptViewMode('FORM'); };
  const handleDeptFormCancel = () => { setDeptViewMode('LIST'); setEditingData(null); };
  const handleSaveDept = (dept: Department) => { if (editingData) dataService.updateDepartment(dept); else dataService.addDepartment(dept); refreshData(); setDeptViewMode('LIST'); setEditingData(null); };

  const openAssignModal = (level: OrgLevel, managerId?: string) => { 
      setAssignTargetLevel(level); 
      setAssignManagerId(managerId || null);
      setAssignSearch(''); 
      setIsAssignModalOpen(true); 
  };

  const handleAssignUser = (userId: string) => {
    // If Assigning via Org Chart modal
    const user = users.find(u => u.id === userId);
    if (user) {
        const updatedUser = { 
            ...user, 
            departmentId: orgSelectedDept, 
            ...(assignTargetLevel ? { orgLevel: assignTargetLevel } : {}), // Update level only if specified
            ...(assignManagerId ? { managerId: assignManagerId } : {}) // Update manager logic
        };
        dataService.updateUser(updatedUser);
        refreshData();
    }
    setIsAssignModalOpen(false);
    setAssignTargetLevel(null);
    setAssignManagerId(null);
  };

  const handleRemoveFromOrg = (user: User) => { const updatedUser = { ...user, orgLevel: undefined, managerId: undefined }; dataService.updateUser(updatedUser); refreshData(); };

  const handleSaveUser = (user: User) => { if (editingData) dataService.updateUser(user); else dataService.addUser(user); refreshData(); setUserViewMode('LIST'); setEditingData(null); };
  const handleSaveJob = (job: JobProfile) => { if (editingData) dataService.updateJobProfile(job); else dataService.addJobProfile(job); refreshData(); setJobViewMode('LIST'); setEditingData(null); };
  const handleSaveSkill = (skill: Skill) => { if (editingData) dataService.updateSkill(skill); else dataService.addSkill(skill); refreshData(); setSkillViewMode('LIST'); setEditingData(null); };

  // --- Render Functions ---

  const renderUsers = () => {
    if (userViewMode === 'FORM') return <UserForm initialData={editingData} onSave={handleSaveUser} onCancel={handleUserFormCancel} />;
    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-bold text-slate-800">Employee Directory</h3>
            <button onClick={handleAddUser} className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1"><Plus size={14}/> Add Employee</button>
        </div>
        <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-500 font-medium"><tr><th className="p-4">Name</th><th className="p-4">Role</th><th className="p-4">Job Profile</th><th className="p-4">Status</th><th className="p-4 text-right">Action</th></tr></thead>
            <tbody className="divide-y divide-slate-100">
            {users.map(u => (
                <tr key={u.id} className="hover:bg-slate-50">
                <td className="p-4 font-medium text-slate-900">{u.name} <br/><span className="text-xs font-normal text-slate-500">{u.email}</span></td>
                <td className="p-4"><span className={`px-2 py-1 rounded-full text-xs font-bold ${u.role === Role.ADMIN ? 'bg-slate-100 text-slate-700' : u.role === Role.MANAGER ? 'bg-indigo-50 text-indigo-700' : 'bg-green-50 text-green-700'}`}>{u.role}</span></td>
                <td className="p-4 text-slate-600">{dataService.getJobProfile(u.jobProfileId || '')?.title || '-'}</td>
                <td className="p-4 text-green-600 flex items-center gap-1"><CheckCircle size={14}/> Active</td>
                <td className="p-4 text-right"><button onClick={() => handleEditUser(u)} className="text-blue-600 hover:underline font-medium">Edit</button></td>
                </tr>
            ))}
            </tbody>
        </table>
        </div>
    );
  };

  const renderJobs = () => {
    if (jobViewMode === 'FORM') return <JobForm initialData={editingData} onSave={handleSaveJob} onCancel={handleJobFormCancel} />;
    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 flex justify-between items-center">
