  };

  const renderSkills = () => {
    if (skillViewMode === 'FORM') return <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-300"><div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50"><h3 className="font-bold text-slate-800 text-lg flex items-center gap-2"><button onClick={handleSkillFormCancel} className="mr-2 text-slate-400 hover:text-slate-700 transition-colors"><ArrowLeft size={20}/></button>{editingData ? `Edit Skill: ${editingData.name}` : 'Create New Skill'}</h3></div><div className="p-6"><SkillForm initialData={editingData} onSave={handleSaveSkill} onCancel={handleSkillFormCancel} /></div></div>;
