  const handleAddSkillClick = () => { setEditingData(null); setSkillViewMode('FORM'); };
  const handleSkillFormCancel = () => { setSkillViewMode('LIST'); setEditingData(null); };

  const handleAddDept = () => { setEditingData(null); setDeptViewMode('FORM'); };
  const handleEditDept = (dept: Department) => { setEditingData(dept); setDeptViewMode('FORM'); };
  const handleDeptFormCancel = () => { setDeptViewMode('LIST'); setDeptViewMode('LIST'); setEditingData(null); };
  const handleSaveDept = (dept: Department) => { if (editingData) dataService.updateDepartment(dept); else dataService.addDepartment(dept); refreshData(); setDeptViewMode('LIST'); setEditingData(null); };

  const openAssignModal = (level: OrgLevel, managerId?: string) => { 
      setAssignTargetLevel(level); 
      setAssignManagerId(managerId || null);
      setAssignSearch(''); 
      setIsAssignModalOpen(true); 
  };

  const handleAssignUser = (userId: string) => {
    // If Assigning via Org Chart modal
    const user = users.find(u => u.id === userId);
    if (user) {
        const updatedUser = { 
            ...user, 
            departmentId: orgSelectedDept, 
            ...(assignTargetLevel ? { orgLevel: assignTargetLevel } : {}), // Update level only if specified
            ...(assignManagerId ? { managerId: assignManagerId } : {}) // Update manager logic
        };
        dataService.updateUser(updatedUser);
        refreshData();
    }
    setIsAssignModalOpen(false);
    setAssignTargetLevel(null);
    setAssignManagerId(null);
  };

  const handleRemoveFromOrg = (user: User) => { const updatedUser = { ...user, orgLevel: undefined, managerId: undefined }; dataService.updateUser(updatedUser); refreshData(); };

  const handleSaveUser = (user: User) => { if (editingData) dataService.updateUser(user); else dataService.addUser(user); refreshData(); setUserViewMode('LIST'); setEditingData(null); };
  const handleSaveJob = (job: JobProfile) => { if (editingData) dataService.updateJobProfile(job); else dataService.addJobProfile(job); refreshData(); setJobViewMode('LIST'); setEditingData(null); };
  const handleSaveSkill = (skill: Skill) => { if (editingData) dataService.updateSkill(skill); else dataService.addSkill(skill); refreshData(); setSkillViewMode('LIST'); setEditingData(null); };

  // --- Render Functions ---

  const renderUsers = () => {
    if (userViewMode === 'FORM') return <UserForm initialData={editingData} onSave={handleSaveUser} onCancel={handleUserFormCancel} />;

    // Filter users based on tab
    const filteredUsers = users.filter(u => 
        userFilter === 'PENDING' 
            ? u.status === 'PENDING' 
            : u.status === 'ACTIVE'
    );

    const pendingCount = users.filter(u => u.status === 'PENDING').length;

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100">
            <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-slate-800">User Management</h3>
                <button onClick={handleAddUser} className="text-xs bg-slate-900 text-white px-3 py-1.5 rounded hover:bg-slate-700 flex items-center gap-1"><Plus size={14}/> Add Manually</button>
            </div>

            <div className="flex gap-2">
                <button 
                    onClick={() => setUserFilter('ACTIVE')}
                    className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 ${userFilter === 'ACTIVE' ? 'bg-teal-50 text-teal-700' : 'text-slate-500 hover:bg-slate-50'}`}
                >
                    <CheckCircle size={16}/> Active Employees
                </button>
                <button 
                    onClick={() => setUserFilter('PENDING')}
                    className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 ${userFilter === 'PENDING' ? 'bg-amber-50 text-amber-700' : 'text-slate-500 hover:bg-slate-50'}`}
                >
                    <AlertCircle size={16}/> Pending Requests
                    {pendingCount > 0 && <span className="bg-amber-500 text-white text-[10px] px-1.5 py-0.5 rounded-full">{pendingCount}</span>}
                </button>
            </div>
        </div>

        {filteredUsers.length > 0 ? (
            <table className="w-full text-left text-sm">
                <thead className="bg-slate-50 text-slate-500 font-medium"><tr><th className="p-4">Name</th><th className="p-4">Role</th><th className="p-4">Job Profile</th><th className="p-4">Status</th><th className="p-4 text-right">Action</th></tr></thead>
                <tbody className="divide-y divide-slate-100">
                {filteredUsers.map(u => (
                    <tr key={u.id} className="hover:bg-slate-50">
                    <td className="p-4 font-medium text-slate-900">{u.name} <br/><span className="text-xs font-normal text-slate-500">{u.email}</span></td>
                    <td className="p-4"><span className={`px-2 py-1 rounded-full text-xs font-bold ${u.role === Role.ADMIN ? 'bg-slate-100 text-slate-700' : u.role === Role.MANAGER ? 'bg-indigo-50 text-indigo-700' : 'bg-green-50 text-green-700'}`}>{u.role}</span></td>
                    <td className="p-4 text-slate-600">{dataService.getJobProfile(u.jobProfileId || '')?.title || '-'}</td>
                    <td className="p-4">
                        {u.status === 'PENDING' ? (
                            <span className="flex items-center gap-1 text-amber-600 font-bold text-xs"><AlertCircle size={14}/> Awaiting Approval</span>
                        ) : (
                            <span className="flex items-center gap-1 text-green-600 font-medium text-xs"><CheckCircle size={14}/> Active</span>
                        )}
                    </td>
                    <td className="p-4 text-right">
                        <button onClick={() => handleEditUser(u)} className={`font-medium ${u.status === 'PENDING' ? 'bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 text-xs' : 'text-blue-600 hover:underline'}`}>
                            {u.status === 'PENDING' ? 'Approve' : 'Edit'}
                        </button>
                    </td>
                    </tr>
                ))}
                </tbody>
            </table>
        ) : (
            <div className="p-12 text-center text-slate-400 flex flex-col items-center">
                 <Users size={32} className="mb-2 opacity-20"/>
                 <p>{userFilter === 'PENDING' ? 'No pending approval requests.' : 'No active users found.'}</p>
            </div>
        )}
        </div>
    );
  };

  const renderJobs = () => {
    if (jobViewMode === 'FORM') return <JobForm initialData={editingData} onSave={handleSaveJob} onCancel={handleJobFormCancel} />;
    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-bold text-slate-800">Job Profiles & Requirements</h3>
            <button onClick={handleAddJob} className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1"><Plus size={14}/> Create Profile</button>
        </div>
        <div className="divide-y divide-slate-100">
            {jobs.map(job => (
                <div key={job.id} className="p-6 hover:bg-slate-50 transition-colors group">
                    <div className="flex justify-between items-start mb-4">
                        <div><h4 className="font-bold text-lg text-slate-800">{job.title}</h4><p className="text-sm text-slate-500">{job.description}</p></div>
                        <button onClick={() => handleEditJob(job)} className="text-sm text-slate-400 hover:text-teal-600 border border-slate-200 rounded px-3 py-1 hover:bg-white transition-colors">Edit Profile</button>
                    </div>
                    <div className="flex flex-wrap gap-2">
                        {Object.entries(job.requirements).map(([level, skills]) => (
                            <div key={level} className="bg-slate-50 rounded-lg p-2 border border-slate-200">
                                <p className="text-xs font-bold text-slate-500 uppercase mb-1">{ORG_LEVEL_LABELS[level as OrgLevel]}</p>
                                <div className="flex flex-wrap gap-1">
                                    {skills && skills.length > 0 ? skills.map(s => {
                                        const skillName = dataService.getSkill(s.skillId)?.name;
                                        return (
                                            <span key={s.skillId} className="bg-white px-2 py-0.5 rounded border border-slate-200 text-[10px] text-slate-700">
                                                {skillName} (L{s.requiredLevel})
                                            </span>
                                        );
                                    }) : <span className="text-[10px] text-slate-400">No skills</span>}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            ))}
        </div>
        </div>
    );
  };

  const renderSkills = () => {
    if (skillViewMode === 'FORM') return <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-300"><div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50"><h3 className="font-bold text-slate-800 text-lg flex items-center gap-2"><button onClick={handleSkillFormCancel} className="mr-2 text-slate-400 hover:text-slate-700 transition-colors"><ArrowLeft size={20}/></button>{editingData ? `Edit Skill: ${editingData.name}` : 'Create New Skill'}</h3></div><div className="p-6"><SkillForm initialData={editingData} onSave={handleSaveSkill} onCancel={handleSkillFormCancel} /></div></div>;
    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center"><h3 className="font-bold text-slate-800">Competency Library</h3><button onClick={handleAddSkillClick} className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1"><Plus size={14}/> Add Skill</button></div>
            <div className="divide-y divide-slate-100">
                {skills.map((skill: Skill) => (
                    <div key={skill.id} className="p-6 hover:bg-slate-50 transition-colors">
                        <div className="flex justify-between items-start mb-4"><div className="flex items-center gap-3"><div className="w-10 h-10 rounded bg-teal-50 flex items-center justify-center text-teal-600"><ShieldCheck size={20} /></div><div><h4 className="font-bold text-slate-800">{skill.name}</h4><span className="text-xs bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full">{skill.category}</span></div></div><button onClick={() => handleEditSkillClick(skill)} className="text-xs border border-slate-300 rounded px-2 py-1 text-slate-500 hover:text-teal-600 hover:border-teal-600 transition-colors">Edit</button></div>
                        {skill.assessmentQuestion && <div className="mb-4 p-3 bg-blue-50 text-blue-800 text-sm rounded-lg border border-blue-100 italic">"Q: {skill.assessmentQuestion}"</div>}
                        <div className="grid grid-cols-1 md:grid-cols-5 gap-3 mt-4">
                            {[1, 2, 3, 4, 5].map(level => {
                                const lvlData = skill.levels[level] as SkillLevel | undefined;
                                return (
                                    <div key={level} className="bg-white border border-slate-200 rounded-lg p-3 text-xs shadow-sm">
                                        <div className="font-bold text-slate-700 mb-1 flex justify-between"><span>Level {level}</span></div>
                                        <p className="text-slate-500 mb-2 leading-relaxed min-h-[40px]">{lvlData?.description || 'No description'}</p>
                                        {lvlData?.requiredCertificates && (lvlData.requiredCertificates as string[]).length > 0 && (<div className="flex flex-wrap gap-1 mt-2 pt-2 border-t border-slate-100">{(lvlData.requiredCertificates as string[]).map((cert, i) => (<span key={i} className="px-1.5 py-0.5 bg-indigo-50 text-indigo-600 rounded text-[10px] font-medium">{cert}</span>))}</div>)}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
  };

  const renderDepartments = () => {
    if (deptViewMode === 'FORM') return <DepartmentForm initialData={editingData} onSave={handleSaveDept} onCancel={handleDeptFormCancel} />;
    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center"><h3 className="font-bold text-slate-800">Departments</h3><button onClick={handleAddDept} className="text-xs bg-teal-600 text-white px-3 py-1.5 rounded hover:bg-teal-700 flex items-center gap-1"><Plus size={14}/> Add Department</button></div>
            <div className="divide-y divide-slate-100">
                {departments.map(dept => (
                    <div key={dept.id} className="p-6 hover:bg-slate-50 transition-colors flex justify-between items-center group">
                        <div className="flex items-center gap-4"><div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center"><Building2 size={24} /></div><div><h4 className="font-bold text-lg text-slate-800">{dept.name}</h4><p className="text-xs text-slate-500">{users.filter(u => u.departmentId === dept.id).length} Employees assigned</p></div></div>
                        <button onClick={() => handleEditDept(dept)} className="text-slate-400 hover:text-teal-600 p-2 rounded-full hover:bg-slate-100 transition-colors"><Edit2 size={18} /></button>
                    </div>
                ))}
                {departments.length === 0 && <div className="p-12 text-center text-slate-400">No departments found. Create one to get started.</div>}
            </div>
        </div>
    );
  };

  const renderOrg = () => {
    // Current Department
    const currentDeptName = departments.find(d => d.id === orgSelectedDept)?.name || 'Unknown';
    const deptUsers: User[] = users.filter(u => u.departmentId === orgSelectedDept && u.status === 'ACTIVE');

    // Filter Users for Modal
    const assignableUsers: User[] = (users || []).filter(u => 
        u.status === 'ACTIVE' && 
        (assignSearch === '' || u.name.toLowerCase().includes(assignSearch.toLowerCase()))
    );

    // Helper to render tree node
    const renderNode = (user: User, depth: number) => {
        // Find direct reports: Users in this dept whose managerId matches current user
        const subordinates: User[] = (deptUsers || []).filter(u => u.managerId === user.id);
        const matchesSearch = orgSearch === '' || user.name.toLowerCase().includes(orgSearch.toLowerCase()) || subordinates.some(sub => sub.name.toLowerCase().includes(orgSearch.toLowerCase())); // Simple bubble up search logic

        if (!matchesSearch && orgSearch !== '') return null;

        return (
            <div key={user.id} className="relative flex flex-col items-center">
                <div className={`
                    relative z-10 flex flex-col items-center p-4 rounded-xl border-2 transition-all group
                    ${user.name.toLowerCase().includes(orgSearch.toLowerCase()) && orgSearch ? 'border-teal-500 bg-teal-50 ring-2 ring-teal-200' : 'border-slate-200 bg-white hover:border-teal-300'}
                `}>
                    <div className="flex items-center gap-3 mb-2">
                         <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-600 font-bold border border-slate-200">
                             {user.name.charAt(0)}
                         </div>
                         <div className="text-center">
                             <p className="font-bold text-slate-800 text-sm">{user.name}</p>
                             <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">
                                {user.orgLevel ? ORG_LEVEL_LABELS[user.orgLevel] : 'Unassigned'}
                             </p>
                         </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="flex gap-2 mt-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button 
                             onClick={() => openAssignModal('FR', user.id)} // Default to FR for child, user.id as manager
                             className="p-1 bg-teal-50 text-teal-600 rounded hover:bg-teal-100"
                             title="Add Subordinate"
                         >
                             <UserPlus size={14} />
                         </button>
                         <button 
                             onClick={() => handleRemoveFromOrg(user)}
                             className="p-1 bg-red-50 text-red-500 rounded hover:bg-red-100"
                             title="Remove from Hierarchy"
                         >
                             <X size={14} />
                         </button>
                    </div>
                </div>

                {subordinates && subordinates.length > 0 && (
                    <div className="flex flex-col items-center mt-4">
                        {/* Connector Down */}
                        <div className="w-px h-4 bg-slate-300 -mt-4 mb-4"></div>

                        {/* Children Container */}
                        <div className="flex gap-8 relative">
                            {/* Horizontal Line connecting children */}
                            {subordinates.length > 1 && (
                                <div className="absolute top-0 left-0 right-0 h-px bg-slate-300 mx-[calc(50%/2)] transform translate-y-[-1px]"></div> 
                                /* Note: Pure CSS lines for dynamic trees are tricky without fixed widths, using simple spacing for now */
                            )}

                            {(subordinates as User[]).map((sub, idx) => (
                                <div key={sub.id} className="relative flex flex-col items-center">
                                    {/* Connector Top for child */}
                                    <div className="w-px h-4 bg-slate-300 absolute -top-4"></div>
                                    {renderNode(sub, depth + 1)}
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        );
    };

    // Find Root Nodes: Users in this dept who do NOT have a manager IN THIS SAME DEPT
    // This allows for external managers (like a GM managing multiple depts) to serve as roots if they aren't 'in' the dept list,
    // OR handles the top-most person in the department.
    const roots: User[] = (deptUsers || []).filter(u => !u.managerId || !deptUsers.find(d => d.id === u.managerId));

    return (
        <div className="space-y-6">
            <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row justify-between items-center gap-4">
                <div className="flex flex-wrap gap-2 items-center">
                    <span className="text-sm font-bold text-slate-700 mr-2 flex items-center gap-2"><Building2 size={18}/> Department:</span>
                    {departments.map(dept => (<button key={dept.id} onClick={() => setOrgSelectedDept(dept.id)} className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-colors ${orgSelectedDept === dept.id ? 'bg-slate-800 text-white shadow-md' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>{dept.name}</button>))}
                </div>
                <div className="relative w-full md:w-64"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} /><input type="text" value={orgSearch} onChange={(e) => setOrgSearch(e.target.value)} placeholder="Search chart..." className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"/></div>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8 min-h-[600px] overflow-auto custom-scrollbar">
                 <h2 className="text-xl font-bold text-slate-800 mb-8 border-b border-slate-100 pb-4 w-full text-center sticky left-0">{currentDeptName} Reporting Lines</h2>

                 <div className="flex justify-center min-w-max pb-12">
                     {roots && roots.length > 0 ? (
                        <div className="flex gap-12">
                            {(roots as User[]).map(root => renderNode(root, 0))}
                        </div>
                     ) : (
                        <div className="flex flex-col items-center justify-center text-slate-400 italic">
                             <Users size={48} className="mb-4 opacity-20"/>
                             <p>No employees found in this department.</p>
                             <button onClick={handleAddUser} className="mt-4 text-teal-600 font-bold hover:underline">Add Employee</button>
                        </div>
                     )}
                 </div>
            </div>

            <Modal isOpen={isAssignModalOpen} onClose={() => setIsAssignModalOpen(false)} title={`Assign ${assignManagerId ? 'Subordinate' : 'User'}`}>
                <div className="space-y-4">
                    <p className="text-sm text-slate-500">
                        {assignManagerId 
                            ? "Select a user to report to this manager." 
                            : "Select a user to add to this department."}
                    </p>
                    <div className="relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} /><input type="text" placeholder="Search users..." className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:ring-1 focus:ring-teal-500 outline-none" value={assignSearch} onChange={(e) => setAssignSearch(e.target.value)}/></div>
                    <div className="space-y-2 max-h-[300px] overflow-y-auto custom-scrollbar border rounded-lg p-2">
                        {(assignableUsers as User[]).map(u => (
                            <button key={u.id} onClick={() => handleAssignUser(u.id)} className="w-full flex items-center justify-between p-3 rounded-lg hover:bg-slate-50 border border-transparent hover:border-slate-200 transition-colors text-left">
                                <div className="flex items-center gap-3"><div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-xs font-bold text-slate-600">{u.name.charAt(0)}</div><div><p className="text-sm font-medium text-slate-900">{u.name}</p><p className="text-xs text-slate-500">{u.departmentId === orgSelectedDept ? 'Current Dept' : dataService.getAllDepartments().find(d=>d.id===u.departmentId)?.name || 'No Dept'} • {u.orgLevel ? ORG_LEVEL_LABELS[u.orgLevel] : 'Unassigned'}</p></div></div>
                                {u.managerId === assignManagerId && u.departmentId === orgSelectedDept && (<CheckCircle size={16} className="text-green-500"/>)}
                            </button>
                        ))}
                    </div>
                </div>
            </Modal>
        </div>
    )
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center space-x-4 border-b border-slate-200 pb-1 overflow-x-auto">
        <button onClick={() => { setActiveView('USERS'); setUserViewMode('LIST'); }} className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 whitespace-nowrap ${activeView === 'USERS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}><Users size={16}/> Users & Approvals</button>
        <button onClick={() => { setActiveView('DEPARTMENTS'); setDeptViewMode('LIST'); }} className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 whitespace-nowrap ${activeView === 'DEPARTMENTS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}><Building2 size={16}/> Departments</button>
        <button onClick={() => { setActiveView('JOBS'); setJobViewMode('LIST'); }} className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 whitespace-nowrap ${activeView === 'JOBS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}><Briefcase size={16}/> Job Profiles</button>
        <button onClick={() => setActiveView('SKILLS')} className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 whitespace-nowrap ${activeView === 'SKILLS' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}><ShieldCheck size={16}/> Skill Library</button>
        <button onClick={() => setActiveView('ORG')} className={`pb-3 px-2 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 whitespace-nowrap ${activeView === 'ORG' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}><Shield size={16}/> Organization Structure</button>
      </div>
      <div className="animate-fade-in">{activeView === 'USERS' && renderUsers()}{activeView === 'DEPARTMENTS' && renderDepartments()}{activeView === 'JOBS' && renderJobs()}{activeView === 'SKILLS' && renderSkills()}{activeView === 'ORG' && renderOrg()}</div>
    </div>
  );
};

