// --- Department Form ---
const DepartmentForm: React.FC<{ initialData?: Department | null, onSave: (d: Department) => void, onCancel: () => void }> = ({ initialData, onSave, onCancel }) => {
    const [name, setName] = useState(initialData?.name || '');
    const [managerId, setManagerId] = useState(initialData?.managerId || '');
    const users = dataService.getAllUsers();
    const managerOptions = users.map(u => ({ value: u.id, label: u.name, subLabel: u.email }));

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSave({ id: initialData?.id || Math.random().toString(36).substr(2, 9), name, managerId: managerId || undefined });
    };

    return (
        <form onSubmit={handleSubmit} className="p-8 space-y-6 bg-white text-sm">
            <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Department Name</label>
                <input required className="w-full px-3 py-2 border border-slate-200 rounded-md focus:ring-2 focus:ring-energy-teal outline-none"
                    value={name} onChange={e => setName(e.target.value)} />
            </div>
            <SearchableSelect label="Department Head (Optional)" options={managerOptions} value={managerId} onChange={setManagerId} placeholder="Select Manager..." />

            <div className="pt-6 flex justify-end gap-3 border-t border-slate-100">
                <button type="button" onClick={onCancel} className="px-6 py-2 text-slate-600 hover:bg-slate-100 rounded-md font-bold uppercase tracking-wide text-xs transition-colors">Cancel</button>
                <button type="submit" className="px-6 py-2 bg-brand-900 text-white rounded-md font-bold uppercase tracking-wide text-xs shadow-md hover:bg-brand-800 flex items-center gap-2 transition-all">
                    <Save size={16} /> Save Dept
                </button>
            </div>
        </form>
    );
};

// --- Main Admin Panel ---
export const AdminPanel: React.FC<{ defaultTab?: string }> = ({ defaultTab = 'USERS' }) => {
  const [activeTab, setActiveTab] = useState(defaultTab);
  const [refreshKey, setRefreshKey] = useState(0); 
  const [modalOpen, setModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'USER' | 'JOB' | 'SKILL' | 'DEPT' | null>(null);
  const [editItem, setEditItem] = useState<any>(null);

  const users = dataService.getAllUsers();
  const jobs = dataService.getAllJobs();
  const skills = dataService.getAllSkills();
  const depts = dataService.getAllDepartments();

  const sortedUsers = [...users].sort((a, b) => {
      if (a.status === 'PENDING' && b.status !== 'PENDING') return -1;
      if (a.status !== 'PENDING' && b.status === 'PENDING') return 1;
      return 0;
  });

  const handleEdit = (type: 'USER' | 'JOB' | 'SKILL' | 'DEPT', item: any) => {
      setModalType(type);
      setEditItem(item);
      setModalOpen(true);
  };

  const handleAdd = (type: 'USER' | 'JOB' | 'SKILL' | 'DEPT') => {
      setModalType(type);
      setEditItem(null);
      setModalOpen(true);
  };

  const handleSave = (item: any) => {
      if (modalType === 'USER') {
          const exists = users.find(u => u.id === item.id);
          if (exists) dataService.updateUser(item);
          else dataService.addUser(item);
      }
      if (modalType === 'JOB') editItem ? dataService.updateJobProfile(item) : dataService.addJobProfile(item);
      if (modalType === 'SKILL') editItem ? dataService.updateSkill(item) : dataService.addSkill(item);
      if (modalType === 'DEPT') editItem ? dataService.updateDepartment(item) : dataService.addDepartment(item);

      setModalOpen(false);
      setRefreshKey(k => k + 1);
  };

  const renderModalContent = () => {
      if (modalType === 'USER') return <UserForm initialData={editItem} onSave={handleSave} onCancel={() => setModalOpen(false)} />;
      if (modalType === 'JOB') return <JobForm initialData={editItem} onSave={handleSave} onCancel={() => setModalOpen(false)} />;
      if (modalType === 'SKILL') return <SkillForm initialData={editItem} onSave={handleSave} onCancel={() => setModalOpen(false)} />;
      if (modalType === 'DEPT') return <DepartmentForm initialData={editItem} onSave={handleSave} onCancel={() => setModalOpen(false)} />;
      return null;
  };

  return (
    <div className="space-y-6">
       <div className="flex justify-between items-center pb-6 border-b border-slate-200">
           <div>
              <h2 className="text-3xl font-bold text-brand-900 tracking-tight">System Administration</h2>
              <p className="text-slate-500 text-sm mt-1">Manage workforce, competency frameworks, and organization structure.</p>
           </div>
           <div className="flex bg-white p-1 rounded-md border border-slate-200 shadow-sm">
               {['USERS', 'JOBS', 'SKILLS', 'DEPTS'].map(tab => (
                   <button key={tab} onClick={() => setActiveTab(tab)} 
                     className={`px-4 py-2 text-xs font-bold uppercase tracking-wider rounded transition-all ${activeTab === tab ? 'bg-brand-800 text-white shadow' : 'text-slate-500 hover:text-brand-900'}`}>
                       {tab === 'USERS' ? 'Workforce' : tab === 'JOBS' ? 'Job Profiles' : tab === 'SKILLS' ? 'Skills' : 'Depts'}
                   </button>
               ))}
           </div>
       </div>

       {/* Content Area */}
       <div className="bg-white rounded-lg shadow-panel border border-slate-200 overflow-hidden min-h-[600px]">
           {/* Toolbar */}
           <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
               <div className="relative max-w-sm w-full">
                   <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                   <input type="text" placeholder="Search records..." className="w-full pl-9 pr-4 py-2 text-sm border border-slate-200 rounded-md focus:outline-none focus:ring-2 focus:ring-energy-teal bg-white transition-all" />
               </div>
               <button onClick={() => handleAdd(activeTab === 'USERS' ? 'USER' : activeTab === 'JOBS' ? 'JOB' : activeTab === 'SKILLS' ? 'SKILL' : 'DEPT')}
                   className="bg-brand-900 hover:bg-brand-800 text-white px-4 py-2 rounded-md text-xs font-bold uppercase tracking-wide shadow-sm flex items-center gap-2 transition-all">
                   <Plus size={16} /> Add {activeTab === 'USERS' ? 'Employee' : activeTab === 'JOBS' ? 'Profile' : activeTab === 'SKILLS' ? 'Skill' : 'Department'}
               </button>
           </div>

           {/* Table */}
           <div className="overflow-x-auto">
               <table className="w-full text-left">
                   <thead className="bg-slate-50 text-slate-500 font-bold text-xs uppercase tracking-wider border-b border-slate-200">
                       <tr>
                           {activeTab === 'USERS' && <> <th className="p-4 pl-6">Employee</th> <th className="p-4">Role & Dept</th> <th className="p-4">Level</th> <th className="p-4">Status</th> </>}
                           {activeTab === 'JOBS' && <> <th className="p-4 pl-6">Job Title</th> <th className="p-4">Department</th> <th className="p-4">Complexity</th> </>}
                           {activeTab === 'SKILLS' && <> <th className="p-4 pl-6">Skill Name</th> <th className="p-4">Category</th> <th className="p-4">Definition</th> </>}
                           {activeTab === 'DEPTS' && <> <th className="p-4 pl-6">Department Name</th> <th className="p-4">Head of Dept</th> </>}
                           <th className="p-4 text-right pr-6"></th>
                       </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-100 text-sm">
                       {activeTab === 'USERS' && sortedUsers.map(user => (
                           <tr key={user.id} className="hover:bg-slate-50 transition-colors group">
                               <td className="p-4 pl-6">
                                   <div className="flex items-center gap-3">
                                       <div className="w-9 h-9 rounded bg-brand-100 flex items-center justify-center text-brand-700 font-bold shadow-sm">
                                           {user.avatarUrl ? <img src={user.avatarUrl} alt="" className="w-full h-full object-cover rounded"/> : user.name[0]}
                                       </div>
                                       <div>
                                           <div className="font-bold text-brand-900 group-hover:text-energy-teal transition-colors">{user.name}</div>
                                           <div className="text-slate-400 text-xs">{user.email}</div>
                                       </div>
                                   </div>
                               </td>
                               <td className="p-4">
                                   <span className="font-semibold text-slate-700 block">{user.role}</span>
                                   <span className="text-slate-400 text-xs">{depts.find(d => d.id === user.departmentId)?.name || 'Unassigned'}</span>
                               </td>
                               <td className="p-4">
                                   <span className="inline-block px-2 py-0.5 bg-slate-100 border border-slate-200 text-slate-600 text-[10px] font-bold uppercase tracking-wide rounded">{user.orgLevel || 'N/A'}</span>
                               </td>
                               <td className="p-4">
                                   {user.status === 'PENDING' ? (
                                       <span className="inline-flex items-center gap-1.5 px-2 py-1 bg-amber-50 text-amber-700 border border-amber-100 text-[10px] font-bold uppercase tracking-wide rounded">
                                           <AlertCircle size={10}/> Pending
                                       </span>
                                   ) : (
                                       <span className="inline-flex items-center gap-1.5 px-2 py-1 bg-green-50 text-green-700 border border-green-100 text-[10px] font-bold uppercase tracking-wide rounded">
                                           <CheckCircle size={10}/> Active
                                       </span>
                                   )}
                               </td>
                               <td className="p-4 text-right pr-6">
                                   <button onClick={() => handleEdit('USER', user)} className="text-slate-400 hover:text-brand-900 p-2 transition-colors"><MoreHorizontal size={18}/></button>
                               </td>
                           </tr>
                       ))}

                       {activeTab === 'JOBS' && jobs.map(job => (
                           <tr key={job.id} className="hover:bg-slate-50 transition-colors group">
                               <td className="p-4 pl-6 font-bold text-brand-900 group-hover:text-energy-teal">{job.title}</td>
                               <td className="p-4 text-slate-600">{depts.find(d => d.id === job.departmentId)?.name}</td>
                               <td className="p-4">
                                   <span className="px-2 py-1 bg-slate-100 text-slate-600 rounded text-[10px] font-bold uppercase tracking-wide">{Object.keys(job.requirements).length} Levels Configured</span>
                               </td>
                               <td className="p-4 text-right pr-6">
                                   <button onClick={() => handleEdit('JOB', job)} className="text-slate-400 hover:text-brand-900 p-2"><Edit2 size={16}/></button>
                               </td>
                           </tr>
                       ))}

                       {activeTab === 'SKILLS' && skills.map(skill => (
                           <tr key={skill.id} className="hover:bg-slate-50 transition-colors group">
                               <td className="p-4 pl-6 font-bold text-brand-900 group-hover:text-energy-teal">{skill.name}</td>
                               <td className="p-4">
                                   <span className="px-2 py-1 bg-brand-50 text-brand-700 border border-brand-100 rounded text-[10px] font-bold uppercase tracking-wide">{skill.category}</span>
                               </td>
                               <td className="p-4 text-slate-500 truncate max-w-xs text-xs">{skill.assessmentQuestion || '-'}</td>
                               <td className="p-4 text-right pr-6">
                                   <button onClick={() => handleEdit('SKILL', skill)} className="text-slate-400 hover:text-brand-900 p-2"><Edit2 size={16}/></button>
                               </td>
                           </tr>
                       ))}

                        {activeTab === 'DEPTS' && depts.map(d => (
                           <tr key={d.id} className="hover:bg-slate-50 transition-colors group">
                               <td className="p-4 pl-6 font-bold text-brand-900 group-hover:text-energy-teal">{d.name}</td>
                               <td className="p-4 text-slate-600">
                                   {users.find(u => u.id === d.managerId)?.name || <span className="text-slate-400 italic text-xs">Vacant Position</span>}
                               </td>
                               <td className="p-4 text-right pr-6">
                                   <button onClick={() => handleEdit('DEPT', d)} className="text-slate-400 hover:text-brand-900 p-2"><Edit2 size={16}/></button>
                               </td>
                           </tr>
                       ))}
                   </tbody>
               </table>
           </div>
       </div>

       <Modal 
         isOpen={modalOpen} 
         onClose={() => setModalOpen(false)} 
         title={
             modalType === 'USER' ? (editItem ? 'Edit Employee Profile' : 'Onboard New Employee') :
             modalType === 'JOB' ? 'Configure Job Profile' :
             modalType === 'SKILL' ? 'Competency Standard Definition' : 'Department Configuration'
         }
       >
           {renderModalContent()}
       </Modal>
