       <Modal 
         isOpen={modalOpen} 
         onClose={() => setModalOpen(false)} 
         title={
             modalType === 'USER' ? (editItem ? 'Edit Employee Profile' : 'Onboard New Employee') :
             modalType === 'JOB' ? 'Configure Job Profile' :
             modalType === 'SKILL' ? 'Competency Standard Definition' : 'Department Configuration'
         }
       >
           {renderModalContent()}
       </Modal>
    </div>
  );
};

