// --- Main Admin Panel ---
export const AdminPanel: React.FC<{ view: string }> = ({ view }) => {
  const [refreshKey, setRefreshKey] = useState(0); 
  const [modalOpen, setModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'USER' | 'JOB' | 'SKILL' | 'DEPT' | null>(null);
  const [editItem, setEditItem] = useState<any>(null);

  const users = dataService.getAllUsers();
  const jobs = dataService.getAllJobs();
  const skills = dataService.getAllSkills();
  const depts = dataService.getAllDepartments();

  const sortedUsers = [...users].sort((a, b) => {
      if (a.status === 'PENDING' && b.status !== 'PENDING') return -1;
      if (a.status !== 'PENDING' && b.status === 'PENDING') return 1;
      return 0;
  });

  const handleEdit = (type: 'USER' | 'JOB' | 'SKILL' | 'DEPT', item: any) => {
      setModalType(type);
      setEditItem(item);
      setModalOpen(true);
  };

  const handleAdd = (type: 'USER' | 'JOB' | 'SKILL' | 'DEPT') => {
      setModalType(type);
      setEditItem(null);
      setModalOpen(true);
  };

  const handleSave = (item: any) => {
      if (modalType === 'USER') {
          const exists = users.find(u => u.id === item.id);
          if (exists) dataService.updateUser(item);
          else dataService.addUser(item);
      }
      if (modalType === 'JOB') editItem ? dataService.updateJobProfile(item) : dataService.addJobProfile(item);
      if (modalType === 'SKILL') editItem ? dataService.updateSkill(item) : dataService.addSkill(item);
      if (modalType === 'DEPT') editItem ? dataService.updateDepartment(item) : dataService.addDepartment(item);

      setModalOpen(false);
      setRefreshKey(k => k + 1);
  };

  const renderModalContent = () => {
      if (modalType === 'USER') return <UserForm initialData={editItem} onSave={handleSave} onCancel={() => setModalOpen(false)} />;
      if (modalType === 'JOB') return <JobForm initialData={editItem} onSave={handleSave} onCancel={() => setModalOpen(false)} />;
      if (modalType === 'SKILL') return <SkillForm initialData={editItem} onSave={handleSave} onCancel={() => setModalOpen(false)} />;
      if (modalType === 'DEPT') return <DepartmentForm initialData={editItem} onSave={handleSave} onCancel={() => setModalOpen(false)} />;
      return null;
  };

  // --- OVERVIEW VIEW ---
  if (view === 'OVERVIEW') {
      return (
        <div className="space-y-8">
            <div className="flex justify-between items-end pb-4 border-b border-slate-200">
                <div>
                    <h2 className="text-3xl font-bold text-brand-900 tracking-tight">System Administration</h2>
                    <p className="text-slate-500 text-sm mt-1">System health and module shortcuts.</p>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                    <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-lg flex items-center justify-center mb-4">
                        <Users size={24} />
                    </div>
                    <h3 className="font-bold text-brand-900 text-lg mb-1">Workforce</h3>
                    <div className="flex items-center gap-2 text-xs font-bold text-blue-600">
                        <span>{users.length} Records</span>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                     <div className="w-12 h-12 bg-purple-50 text-purple-600 rounded-lg flex items-center justify-center mb-4">
                        <Briefcase size={24} />
                    </div>
                    <h3 className="font-bold text-brand-900 text-lg mb-1">Job Profiles</h3>
                    <div className="flex items-center gap-2 text-xs font-bold text-purple-600">
                        <span>{jobs.length} Profiles</span>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                     <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-lg flex items-center justify-center mb-4">
                        <ShieldCheck size={24} />
                    </div>
                    <h3 className="font-bold text-brand-900 text-lg mb-1">Skills Library</h3>
                    <div className="flex items-center gap-2 text-xs font-bold text-emerald-600">
                        <span>{skills.length} Skills</span>
                    </div>
                </div>

                 <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                     <div className="w-12 h-12 bg-orange-50 text-orange-600 rounded-lg flex items-center justify-center mb-4">
