                           {view === 'SKILLS' && <> <th className="p-4 pl-6">Skill Name</th> <th className="p-4">Category</th> <th className="p-4">Definition</th> </>}
                           {view === 'DEPTS' && <> <th className="p-4 pl-6">Department Name</th> <th className="p-4">Head of Dept</th> </>}
